{
  "name": "PesaTrack AI",
  "description": "Smart expense and tax assistant for Kenyans. Automatically tracks M-Pesa, scans receipts, and optimizes KRA tax returns using AI.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Category {
  FOOD = 'Food & Groceries',
  TRANSPORT = 'Transport',
  RENT = 'Rent & Housing',
  UTILITIES = 'Utilities',
  BUSINESS = 'Business',
  MEDICAL = 'Medical',
  EDUCATION = 'Education',
  CHURCH = 'Church/Giving',
  PERSONAL = 'Personal/Lifestyle',
  OTHER = 'Other'
}

export interface Transaction {
  id: string;
  date: string;
  merchant: string;
  amount: number;
  category: Category;
  type: 'expense' | 'income';
  source: 'mpesa' | 'receipt' | 'manual';
  vatAmount?: number;
  isBusiness?: boolean;
}

export interface TaxRelief {
  personalRelief: number;
  insuranceRelief: number;
  mortgageRelief: number;
  pensionRelief: number;
}

export interface TaxReport {
  totalIncome: number;
  totalExpenses: number;
  deductibleExpenses: number;
  estimatedTaxLiability: number;
  reliefsClaimed: number;
  refundPotential: number;
  refundScore: number;
}

export const KENYA_TAX_BANDS = [
  { upTo: 24000, rate: 0.10 },
  { upTo: 32333, rate: 0.25 },
  { upTo: 500000, rate: 0.30 },
  { upTo: 800000, rate: 0.325 },
  { upTo: Infinity, rate: 0.35 }
];

export const PERSONAL_RELIEF_MONTHLY = 2400;
export const SHIF_RATE = 0.0275; // Social Health Insurance Fund

export const CURRENCY = 'KES';

export const LOCAL_MERCHANTS = [
  'Naivas', 'Quickmart', 'Carrefour', 'Shell', 'Rubis', 'TotalEnergies', 
  'Jumia', 'KPLC', 'Zuku', 'Safaricom', 'Airtel'
];

import { GoogleGenAI, Type } from "@google/genai";
import { Category } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeReceipt = async (base64Image: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: "Extract transaction details from this Kenyan receipt. Return JSON." }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          merchant: { type: Type.STRING },
          amount: { type: Type.NUMBER },
          date: { type: Type.STRING },
          vatAmount: { type: Type.NUMBER },
          category: { 
            type: Type.STRING, 
            description: "Categorize into: Food, Transport, Rent, Utilities, Business, Medical, Education, Church, Personal" 
          },
          isBusiness: { type: Type.BOOLEAN }
        },
        required: ["merchant", "amount", "date", "category"]
      }
    }
  });

  return JSON.parse(response.text);
};

export const parseMpesaMessage = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this M-Pesa SMS and extract structured data. 
    Text: "${text}"
    Return JSON with fields: amount (number), merchant (string), date (string), transactionType (expense/income), category (one of the app's categories), referenceId (string).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          amount: { type: Type.NUMBER },
          merchant: { type: Type.STRING },
          date: { type: Type.STRING },
          transactionType: { type: Type.STRING },
          category: { type: Type.STRING },
          referenceId: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

import React, { useState, useEffect } from 'react';
import { Transaction, Category } from './types';
import Dashboard from './components/Dashboard';
import ReceiptScanner from './components/ReceiptScanner';
import MpesaInput from './components/MpesaInput';
import TaxEngine from './components/TaxEngine';
import VoiceCoach from './components/VoiceCoach';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'scan' | 'mpesa' | 'tax' | 'coach'>('home');
  const [transactions, setTransactions] = useState<Transaction[]>([]);

  // Simulated initial data
  useEffect(() => {
    const mockData: Transaction[] = [
      { id: '1', date: '2023-10-25', merchant: 'Naivas Westlands', amount: 4500, category: Category.FOOD, type: 'expense', source: 'receipt', vatAmount: 720 },
      { id: '2', date: '2023-10-26', merchant: 'Rubis Kileleshwa', amount: 3000, category: Category.TRANSPORT, type: 'expense', source: 'mpesa' },
      { id: '3', date: '2023-10-27', merchant: 'Salary - Acme Corp', amount: 150000, category: Category.OTHER, type: 'income', source: 'manual' },
      { id: '4', date: '2023-10-28', merchant: 'Zuku Fiber', amount: 4000, category: Category.UTILITIES, type: 'expense', source: 'mpesa' },
    ];
    setTransactions(mockData);
  }, []);

  const addTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <Dashboard transactions={transactions} />;
      case 'scan': return <ReceiptScanner onAdd={addTransaction} />;
      case 'mpesa': return <MpesaInput onAdd={addTransaction} />;
      case 'tax': return <TaxEngine transactions={transactions} />;
      case 'coach': return <VoiceCoach transactions={transactions} />;
      default: return <Dashboard transactions={transactions} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col pb-20">
      {/* Header */}
      <header className="bg-emerald-600 text-white p-4 shadow-md sticky top-0 z-50">
        <div className="max-w-md mx-auto flex justify-between items-center">
          <h1 className="text-xl font-bold flex items-center gap-2">
            <span className="text-2xl">🇰🇼</span> PesaTrack AI
          </h1>
          <button className="bg-emerald-700 p-2 rounded-full hover:bg-emerald-800">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
