            </svg>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-md mx-auto p-4">
        {renderContent()}
      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 shadow-lg flex justify-around p-2 z-50">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon="home" label="Home" />
        <NavButton active={activeTab === 'scan'} onClick={() => setActiveTab('scan')} icon="camera" label="Scan" />
        <NavButton active={activeTab === 'mpesa'} onClick={() => setActiveTab('mpesa')} icon="chat" label="M-Pesa" />
        <NavButton active={activeTab === 'tax'} onClick={() => setActiveTab('tax')} icon="tax" label="Tax" />
        <NavButton active={activeTab === 'coach'} onClick={() => setActiveTab('coach')} icon="voice" label="Coach" />
