export default App;

import React from 'react';
import { Transaction, Category } from '../types';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip } from 'recharts';
import { CURRENCY } from '../constants';

interface DashboardProps {
  transactions: Transaction[];
}

const COLORS = ['#059669', '#10B981', '#34D399', '#6EE7B7', '#A7F3D0', '#D1FAE5', '#F59E0B', '#EF4444', '#3B82F6', '#8B5CF6'];

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const currentMonthExpenses = transactions
    .filter(t => t.type === 'expense')
    .reduce((sum, t) => sum + t.amount, 0);

  const categoryData = Object.values(Category).map(cat => ({
    name: cat,
    value: transactions
      .filter(t => t.category === cat && t.type === 'expense')
      .reduce((sum, t) => sum + t.amount, 0)
  })).filter(d => d.value > 0);

  const recentTransactions = [...transactions].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()).slice(0, 5);

  return (
    <div className="space-y-6">
      {/* Summary Card */}
      <div className="bg-emerald-600 text-white rounded-3xl p-6 shadow-xl relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-emerald-100 text-sm">Spent this month</p>
          <h2 className="text-3xl font-bold mt-1">{CURRENCY} {currentMonthExpenses.toLocaleString()}</h2>
          <div className="mt-4 flex gap-4">
            <div className="bg-white/20 px-3 py-1 rounded-full text-xs">
              ↓ 12% from last month
            </div>
            <div className="bg-white/20 px-3 py-1 rounded-full text-xs">
              Daily Avg: {CURRENCY} {(currentMonthExpenses / 30).toFixed(0)}
            </div>
          </div>
        </div>
        <div className="absolute top-[-20px] right-[-20px] w-32 h-32 bg-white/10 rounded-full"></div>
      </div>

      {/* Charts Section */}
      <div className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100">
        <h3 className="font-semibold text-gray-700 mb-4">Spending by Category</h3>
        <div className="h-64">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={categoryData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {categoryData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip formatter={(value: number) => `${CURRENCY} ${value}`} />
            </PieChart>
          </ResponsiveContainer>
        </div>
        <div className="grid grid-cols-2 gap-2 mt-4">
          {categoryData.map((d, i) => (
            <div key={d.name} className="flex items-center gap-2 text-xs text-gray-600">
              <span className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }}></span>
              <span className="truncate">{d.name}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Recent Activity */}
      <div>
        <div className="flex justify-between items-center mb-3 px-1">
          <h3 className="font-semibold text-gray-700">Recent Activity</h3>
          <button className="text-emerald-600 text-sm font-medium">See all</button>
        </div>
        <div className="space-y-3">
          {recentTransactions.map(t => (
            <div key={t.id} className="bg-white p-4 rounded-2xl flex items-center gap-4 shadow-sm border border-gray-50">
              <div className={`p-3 rounded-xl ${t.type === 'income' ? 'bg-emerald-100 text-emerald-600' : 'bg-gray-100 text-gray-600'}`}>
                {t.source === 'mpesa' ? '📩' : t.source === 'receipt' ? '📸' : '📝'}
              </div>
              <div className="flex-1">
                <p className="font-medium text-gray-800">{t.merchant}</p>
                <p className="text-xs text-gray-400">{t.date} • {t.category}</p>
              </div>
              <div className={`font-bold ${t.type === 'income' ? 'text-emerald-600' : 'text-gray-800'}`}>
                {t.type === 'expense' ? '-' : '+'}{CURRENCY} {t.amount}
