export default Dashboard;

import React, { useState, useRef } from 'react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction, Category } from '../types';

interface ReceiptScannerProps {
  onAdd: (t: Transaction) => void;
}

const ReceiptScanner: React.FC<ReceiptScannerProps> = ({ onAdd }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      setPreview(reader.result as string);
      setIsScanning(true);
      setError(null);

      try {
        const result = await analyzeReceipt(base64);
        const newTransaction: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: result.date || new Date().toISOString().split('T')[0],
          merchant: result.merchant || 'Unknown Merchant',
          amount: result.amount || 0,
          category: result.category as Category || Category.OTHER,
          type: 'expense',
          source: 'receipt',
          vatAmount: result.vatAmount,
          isBusiness: result.isBusiness
        };
        onAdd(newTransaction);
        setIsScanning(false);
        setPreview(null);
        alert('Receipt added successfully!');
      } catch (err) {
        console.error(err);
        setError('Failed to analyze receipt. Please try again.');
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 text-center">
        <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-4">
          <svg className="w-10 h-10 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
            <circle cx="12" cy="13" r="4" />
          </svg>
        </div>
        <h2 className="text-xl font-bold text-gray-800">Smart Receipt Scanner</h2>
        <p className="text-gray-500 text-sm mt-2">Take a photo of any receipt (Naivas, Shell, Pharmacy) and our AI will extract the data for you.</p>

        <input 
          type="file" 
          accept="image/*" 
          capture="environment" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleFileSelect}
        />

        <button 
          onClick={() => fileInputRef.current?.click()}
          disabled={isScanning}
          className="w-full mt-6 bg-emerald-600 text-white py-4 rounded-2xl font-bold hover:bg-emerald-700 disabled:bg-gray-400 transition-colors shadow-lg"
        >
          {isScanning ? 'Analyzing Receipt...' : 'Take Photo / Upload'}
        </button>

        {error && <p className="text-red-500 text-xs mt-4 font-medium">{error}</p>}
      </div>

      {isScanning && (
        <div className="flex flex-col items-center gap-4 py-8">
          <div className="w-12 h-12 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-sm text-gray-600 animate-pulse font-medium">Extracting amount, merchant & VAT...</p>
        </div>
      )}

      {preview && !isScanning && (
        <div className="rounded-2xl overflow-hidden border border-gray-200">
          <img src={preview} alt="Receipt Preview" className="w-full h-auto opacity-50 grayscale" />
        </div>
      )}

      <div className="bg-emerald-50 p-4 rounded-2xl border border-emerald-100">
        <h4 className="text-emerald-800 font-bold text-sm mb-1">Pro Tip</h4>
        <p className="text-emerald-700 text-xs leading-relaxed">Receipt scanning helps identify VAT-claimable business expenses for your annual tax return.</p>
      </div>
    </div>
  );
};

export default ReceiptScanner;

import React, { useState } from 'react';
import { parseMpesaMessage } from '../services/geminiService';
import { Transaction, Category } from '../types';

interface MpesaInputProps {
  onAdd: (t: Transaction) => void;
}

const MpesaInput: React.FC<MpesaInputProps> = ({ onAdd }) => {
  const [smsText, setSmsText] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handlePaste = async () => {
    if (!smsText.trim()) return;
    setIsAnalyzing(true);
    try {
      const result = await parseMpesaMessage(smsText);
      const newTransaction: Transaction = {
        id: result.referenceId || Math.random().toString(36).substr(2, 9),
        date: result.date || new Date().toISOString().split('T')[0],
        merchant: result.merchant || 'M-Pesa Transaction',
        amount: result.amount || 0,
        category: result.category as Category || Category.OTHER,
        type: (result.transactionType === 'income' ? 'income' : 'expense'),
        source: 'mpesa'
      };
      onAdd(newTransaction);
      setSmsText('');
      alert('M-Pesa transaction recorded!');
    } catch (err) {
      console.error(err);
      alert('Could not parse SMS. Please check format.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-800 mb-2">M-Pesa Analyzer</h2>
        <p className="text-gray-500 text-sm mb-6">Paste your M-Pesa SMS messages here to automatically track spending.</p>

        <textarea 
          value={smsText}
          onChange={(e) => setSmsText(e.target.value)}
          placeholder="e.g. OBI1234567 Confirmed. You have paid KES 2,500 to Naivas Supermarket..."
          className="w-full h-40 p-4 bg-gray-50 border border-gray-200 rounded-2xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent outline-none transition-all resize-none text-sm leading-relaxed"
        />

        <button 
          onClick={handlePaste}
          disabled={isAnalyzing || !smsText.trim()}
          className="w-full mt-4 bg-emerald-600 text-white py-4 rounded-2xl font-bold hover:bg-emerald-700 disabled:bg-gray-300 transition-colors shadow-md"
        >
          {isAnalyzing ? 'Analyzing SMS...' : 'Process SMS'}
        </button>
      </div>

      <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100">
        <div className="flex gap-3">
          <div className="bg-blue-600 text-white w-6 h-6 rounded-full flex items-center justify-center shrink-0 mt-0.5">
            <span className="text-[10px]">!</span>
          </div>
          <div>
            <h4 className="text-blue-900 font-bold text-sm mb-1">Privacy First</h4>
            <p className="text-blue-800 text-xs leading-relaxed">We only extract amount, merchant, and category. Your reference numbers and balance are not stored on our servers.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MpesaInput;

import React, { useMemo } from 'react';
import { Transaction, Category } from '../types';
import { KENYA_TAX_BANDS, PERSONAL_RELIEF_MONTHLY, CURRENCY } from '../constants';

interface TaxEngineProps {
  transactions: Transaction[];
}

const TaxEngine: React.FC<TaxEngineProps> = ({ transactions }) => {
  const stats = useMemo(() => {
    const totalIncome = transactions
      .filter(t => t.type === 'income')
      .reduce((sum, t) => sum + t.amount, 0);

    const deductibleExpenses = transactions
      .filter(t => t.isBusiness || t.category === Category.BUSINESS)
      .reduce((sum, t) => sum + t.amount, 0);

    const taxableIncome = Math.max(0, totalIncome - deductibleExpenses);

    // Simple yearly PAYE estimation
    let taxLiability = 0;
    let remainingIncome = taxableIncome;
    let prevBand = 0;

    for (const band of KENYA_TAX_BANDS) {
      const currentBandLimit = band.upTo === Infinity ? remainingIncome : band.upTo - prevBand;
      const taxableInBand = Math.min(remainingIncome, currentBandLimit);
      taxLiability += taxableInBand * band.rate;
      remainingIncome -= taxableInBand;
      prevBand = band.upTo;
      if (remainingIncome <= 0) break;
    }

    const personalRelief = 2400 * 12; // Yearly
    const estimatedTax = Math.max(0, taxLiability - personalRelief);

    return {
      totalIncome,
      deductibleExpenses,
      estimatedTax,
      refundProbability: totalIncome > 0 ? (deductibleExpenses / totalIncome) * 100 : 0
    };
  }, [transactions]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-800 mb-6">Tax Optimization Engine 🇰🇪</h2>

        <div className="grid grid-cols-2 gap-4 mb-6">
          <div className="bg-gray-50 p-4 rounded-2xl">
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Estimated Tax</p>
            <p className="text-lg font-bold text-gray-800">{CURRENCY} {stats.estimatedTax.toLocaleString()}</p>
          </div>
          <div className="bg-emerald-50 p-4 rounded-2xl">
            <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider">Deductible</p>
            <p className="text-lg font-bold text-emerald-600">{CURRENCY} {stats.deductibleExpenses.toLocaleString()}</p>
