import React, { useMemo } from 'react';
import { Transaction, Category, UserProfile, EmploymentType } from '../types';
import { KENYA_TAX_BANDS, PERSONAL_RELIEF_MONTHLY, CURRENCY } from '../constants';

interface TaxEngineProps {
  transactions: Transaction[];
  profile?: UserProfile;
}

const TaxEngine: React.FC<TaxEngineProps> = ({ transactions, profile }) => {
  const stats = useMemo(() => {
    // If salaried, we assume monthlyIncome is Gross Pay
    // If freelancer/SME, we use transactions for income but default to profile income if none found
    const transactionsIncome = transactions
      .filter(t => t.type === 'income')
      .reduce((sum, t) => sum + t.amount, 0);

    const yearlyIncome = transactionsIncome || (profile ? profile.monthlyIncome * 12 : 0);

    const deductibleExpenses = transactions
      .filter(t => t.isBusiness || t.category === Category.BUSINESS)
      .reduce((sum, t) => sum + t.amount, 0);

    const taxableIncome = Math.max(0, yearlyIncome - deductibleExpenses);

    // Yearly PAYE estimation
    let taxLiability = 0;
    let remainingIncome = taxableIncome;
    let prevBand = 0;

    for (const band of KENYA_TAX_BANDS) {
      const currentBandLimit = band.upTo === Infinity ? remainingIncome : band.upTo - prevBand;
      const taxableInBand = Math.min(remainingIncome, currentBandLimit);
      taxLiability += taxableInBand * band.rate;
      remainingIncome -= taxableInBand;
      prevBand = band.upTo;
      if (remainingIncome <= 0) break;
    }

    const personalRelief = 2400 * 12; // Yearly
    const estimatedTax = Math.max(0, taxLiability - personalRelief);

    return {
      yearlyIncome,
      deductibleExpenses,
      estimatedTax,
      refundProbability: yearlyIncome > 0 ? (deductibleExpenses / yearlyIncome) * 100 : 0
    };
  }, [transactions, profile]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
        <h2 className="text-xl font-bold text-gray-800 mb-6">Tax Optimization Engine 🇰🇪</h2>

        {profile && (
          <div className="mb-4 bg-emerald-50 px-3 py-2 rounded-xl text-[10px] text-emerald-800 font-bold flex justify-between items-center">
            <span>PROFILING: {profile.employmentType.toUpperCase()}</span>
            <span>{profile.industry.toUpperCase()}</span>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4 mb-6">
          <div className="bg-gray-50 p-4 rounded-2xl">
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">Estimated Tax</p>
            <p className="text-lg font-bold text-gray-800">{CURRENCY} {stats.estimatedTax.toLocaleString()}</p>
          </div>
          <div className="bg-emerald-50 p-4 rounded-2xl">
            <p className="text-[10px] text-emerald-600 font-bold uppercase tracking-wider">Deductible</p>
            <p className="text-lg font-bold text-emerald-600">{CURRENCY} {stats.deductibleExpenses.toLocaleString()}</p>
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex justify-between items-end">
            <h3 className="text-sm font-semibold text-gray-600">Refund Probability Score™</h3>
            <span className="text-2xl font-black text-emerald-600">{stats.refundProbability.toFixed(0)}%</span>
          </div>
          <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden">
            <div 
              className="h-full bg-emerald-500 rounded-full transition-all duration-1000" 
              style={{ width: `${Math.min(100, stats.refundProbability)}%` }}
            />
          </div>
          <p className="text-xs text-gray-500 italic">"Based on your profile as a {profile?.employmentType || 'taxpayer'}, you have a {stats.refundProbability > 50 ? 'high' : 'moderate'} chance of qualifying for a KRA refund."</p>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
        <h3 className="font-bold text-gray-800 mb-4">Refund Strategy</h3>
        <ul className="space-y-4">
          <StrategyItem 
            title="Insurance Relief" 
            desc="You haven't uploaded an insurance certificate. This could save you up to KES 5,000/year."
            status="missing"
          />
          <StrategyItem 
            title="Mortgage Interest" 
            desc="Deduct up to KES 300,000 yearly if you have an active mortgage."
            status="available"
          />
          {profile?.employmentType === EmploymentType.FREELANCER && (
            <StrategyItem 
              title="Business Expenses" 
              desc="As a freelancer, ensure all internet and home office costs are categorized correctly."
              status="action"
            />
          )}
          <StrategyItem 
            title="VAT Claim" 
            desc="Your fuel receipts have claimable VAT. Tag them as 'Business'."
            status="action"
          />
        </ul>
      </div>

      <button className="w-full bg-gray-900 text-white py-4 rounded-2xl font-bold hover:bg-black transition-colors shadow-lg">
        Generate iTax Filing Schedule
      </button>
    </div>
  );
};

const StrategyItem: React.FC<{ title: string; desc: string; status: 'missing' | 'available' | 'action' }> = ({ title, desc, status }) => {
  const colorMap = {
    missing: 'text-amber-600 bg-amber-100',
    available: 'text-blue-600 bg-blue-100',
    action: 'text-emerald-600 bg-emerald-100'
  };

  return (
    <li className="flex gap-4">
      <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${colorMap[status]}`}>
        {status === 'missing' ? '?' : status === 'available' ? '+' : '✓'}
      </div>
      <div>
        <h4 className="text-sm font-bold text-gray-800">{title}</h4>
        <p className="text-xs text-gray-500 leading-relaxed">{desc}</p>
      </div>
    </li>
  );
};

