import React, { useMemo } from 'react';
import { Transaction, Category, UserProfile, EmploymentType } from '../types';
import { KENYA_TAX_BANDS, CURRENCY } from '../constants';

interface TaxEngineProps {
  transactions: Transaction[];
  profile: UserProfile;
}

const TaxEngine: React.FC<TaxEngineProps> = ({ transactions, profile }) => {
  const stats = useMemo(() => {
    const transactionsIncome = transactions
      .filter(t => t.type === 'income')
      .reduce((sum, t) => sum + t.amount, 0);

    const yearlyIncome = transactionsIncome || (profile.monthlyIncome * 12);

    const deductibleExpenses = transactions
      .filter(t => t.isBusiness || t.category === Category.BUSINESS)
      .reduce((sum, t) => sum + t.amount, 0);

    const taxableIncome = Math.max(0, yearlyIncome - deductibleExpenses);

    let taxLiability = 0;
    let remainingIncome = taxableIncome;
    let prevBand = 0;

    for (const band of KENYA_TAX_BANDS) {
      const currentBandLimit = band.upTo === Infinity ? remainingIncome : band.upTo - prevBand;
      const taxableInBand = Math.min(remainingIncome, currentBandLimit);
      taxLiability += taxableInBand * band.rate;
      remainingIncome -= taxableInBand;
      prevBand = band.upTo;
      if (remainingIncome <= 0) break;
    }

    const personalRelief = 2400 * 12; 
    const estimatedTax = Math.max(0, taxLiability - personalRelief);

    return {
      yearlyIncome,
      deductibleExpenses,
      estimatedTax,
      refundProbability: 82 // Mocked for design demo
    };
  }, [transactions, profile]);

  return (
    <div className="space-y-6">
      {/* Refund Hero Card */}
      <div className="bg-emerald-600 text-white rounded-[40px] p-8 shadow-2xl shadow-emerald-200 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-emerald-100 text-xs font-bold uppercase tracking-widest mb-2">Estimated Tax Refund</p>
          <h2 className="text-4xl font-black mb-6">{CURRENCY} 18,400</h2>

          <div className="flex justify-between items-center mb-2">
            <span className="text-xs font-bold uppercase tracking-widest">Refund Probability</span>
            <span className="text-lg font-black">{stats.refundProbability}%</span>
          </div>
          <div className="w-full h-3 bg-white/20 rounded-full overflow-hidden">
            <div className="h-full bg-emerald-300 w-[82%] rounded-full"></div>
          </div>
          <p className="text-[10px] text-emerald-100/70 mt-3 font-medium">"Your refund likelihood is HIGH based on your deductible business expenses."</p>
        </div>
        {/* Decorator Circles */}
        <div className="absolute top-[-20px] right-[-20px] w-32 h-32 bg-white/10 rounded-full"></div>
        <div className="absolute bottom-[-40px] left-[-20px] w-48 h-48 bg-emerald-500 rounded-full blur-2xl"></div>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-white p-5 rounded-[32px] border border-gray-100 shadow-sm">
          <p className="text-gray-400 text-[10px] font-bold uppercase tracking-wider mb-1">PAYE Estimate</p>
          <p className="text-lg font-black text-gray-800">{CURRENCY} {stats.estimatedTax.toLocaleString()}</p>
        </div>
        <div className="bg-white p-5 rounded-[32px] border border-gray-100 shadow-sm">
          <p className="text-gray-400 text-[10px] font-bold uppercase tracking-wider mb-1">Deductible</p>
          <p className="text-lg font-black text-emerald-600">{CURRENCY} {stats.deductibleExpenses.toLocaleString()}</p>
        </div>
      </div>

      <div className="bg-white p-6 rounded-[32px] shadow-sm border border-gray-100">
        <h3 className="font-black text-gray-800 mb-6 uppercase tracking-tight text-sm">Action Plan to Maximize Refund</h3>
        <ul className="space-y-6">
          <StrategyItem 
            title="Insurance Relief" 
            desc="Add your NHIF/SHIF or life insurance statements to increase your refund by KES 5,000+."
            status="missing"
          />
          <StrategyItem 
            title="Mortgage Interest" 
            desc="Claim up to KES 25,000 monthly if you are paying off a home loan."
            status="available"
          />
          <StrategyItem 
            title="VAT Claim" 
            desc="You have 3 fuel receipts from Rubis not tagged as business. These are claimable."
            status="action"
          />
        </ul>
      </div>

      <button className="w-full bg-gray-900 text-white py-5 rounded-[28px] font-black uppercase tracking-widest text-sm hover:bg-black transition-all active:scale-95 shadow-xl shadow-gray-200">
        Prepare 2024 Tax Return
      </button>

      <p className="text-[10px] text-center text-gray-400 px-8 font-medium italic">
        * Estimates are based on current data. Always verify with your iTax login before final submission.
      </p>
    </div>
  );
};

