import React, { useState, useRef } from 'react';
import { analyzeReceipt } from '../services/geminiService';
import { Transaction, Category } from '../types';

interface ReceiptScannerProps {
  onAdd: (t: Transaction) => void;
}

const ReceiptScanner: React.FC<ReceiptScannerProps> = ({ onAdd }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [preview, setPreview] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async () => {
      const base64 = (reader.result as string).split(',')[1];
      setPreview(reader.result as string);
      setIsScanning(true);
      setError(null);

      try {
        const result = await analyzeReceipt(base64);
        const newTransaction: Transaction = {
          id: Math.random().toString(36).substr(2, 9),
          date: result.date || new Date().toISOString().split('T')[0],
          merchant: result.merchant || 'Unknown Merchant',
          amount: result.amount || 0,
          category: result.category as Category || Category.OTHER,
          type: 'expense',
          source: 'receipt',
          vatAmount: result.vatAmount,
          isBusiness: result.isBusiness
        };
        onAdd(newTransaction);
        setIsScanning(false);
        setPreview(null);
      } catch (err) {
        console.error(err);
        setError('Failed to analyze. Ensure receipt is clear.');
        setIsScanning(false);
      }
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-100 text-center relative overflow-hidden">
        <div className="w-24 h-24 bg-emerald-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
          <svg className="w-10 h-10 text-emerald-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
            <circle cx="12" cy="13" r="4" />
          </svg>
        </div>

        <h2 className="text-2xl font-black text-gray-900 tracking-tight">Receipt Scanner</h2>
        <p className="text-gray-400 text-xs font-medium mt-3 px-4">Place receipt on a flat surface. Our AI identifies Merchant & VAT automatically.</p>

        <input 
          type="file" 
          accept="image/*" 
          capture="environment" 
          className="hidden" 
          ref={fileInputRef}
          onChange={handleFileSelect}
        />

        <button 
          onClick={() => fileInputRef.current?.click()}
          disabled={isScanning}
          className="w-full mt-8 bg-emerald-600 text-white py-5 rounded-[28px] font-black uppercase tracking-widest text-sm hover:bg-emerald-700 disabled:bg-gray-200 transition-all shadow-xl shadow-emerald-100 active:scale-95"
        >
          {isScanning ? 'Extracting Data...' : '📸 Capture Receipt'}
        </button>

        {error && <div className="mt-4 p-3 bg-red-50 text-red-600 text-[10px] font-bold rounded-2xl border border-red-100">⚠️ {error}</div>}
      </div>

      {isScanning && (
        <div className="flex flex-col items-center gap-4 py-6">
          <div className="relative w-16 h-16">
            <div className="absolute inset-0 border-4 border-emerald-600/20 rounded-full"></div>
            <div className="absolute inset-0 border-4 border-emerald-600 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest animate-pulse">Running OCR & Tax Analysis</p>
        </div>
      )}

      {preview && !isScanning && (
        <div className="rounded-[32px] overflow-hidden border-4 border-white shadow-2xl relative">
          <div className="absolute inset-0 bg-emerald-600/10 mix-blend-overlay"></div>
          <img src={preview} alt="Receipt Preview" className="w-full h-auto" />
          <div className="absolute top-4 right-4 bg-emerald-600 text-white p-2 rounded-full shadow-lg">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
            </svg>
          </div>
        </div>
      )}

      <div className="bg-emerald-50/50 p-6 rounded-[32px] border border-emerald-100/50">
        <h4 className="text-emerald-900 font-black text-xs uppercase tracking-wider mb-2">Did you know?</h4>
        <p className="text-emerald-700/80 text-[11px] font-medium leading-relaxed">Freelancers can claim up to 100% of business-related expenses. Scanning keeps your documents audit-ready for KRA.</p>
      </div>
    </div>
  );
};

export default ReceiptScanner;

import React, { useState } from 'react';
import { UserProfile, EmploymentType } from '../types';
import { CURRENCY } from '../constants';

interface ProfileProps {
  profile: UserProfile;
  onSave: (p: UserProfile) => void;
}

const Profile: React.FC<ProfileProps> = ({ profile, onSave }) => {
  const [editedProfile, setEditedProfile] = useState<UserProfile>({ ...profile });
  const [isSaved, setIsSaved] = useState(false);
  const [newGoal, setNewGoal] = useState('');

  const industries = [
    'Technology', 'Agriculture', 'Healthcare', 'Education', 
    'Transport & Logistics', 'Construction', 'Retail', 'Creative Arts',
    'Hospitality', 'Public Service', 'Finance', 'Manufacturing', 'Other'
  ];

  const handleSave = () => {
    onSave(editedProfile);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const addGoal = () => {
    if (newGoal.trim()) {
      setEditedProfile({
        ...editedProfile,
        financialGoals: [...editedProfile.financialGoals, newGoal.trim()]
      });
      setNewGoal('');
    }
  };

  const removeGoal = (index: number) => {
    setEditedProfile({
      ...editedProfile,
      financialGoals: editedProfile.financialGoals.filter((_, i) => i !== index)
    });
  };

  return (
    <div className="space-y-6 pb-8">
      {/* Premium Profile Header */}
      <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-100 flex flex-col items-center relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4">
          <div className="bg-emerald-50 text-emerald-600 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-emerald-100">Verified User</div>
        </div>
        <div className="w-24 h-24 bg-emerald-100 rounded-full flex items-center justify-center mb-4 text-emerald-600 border-8 border-emerald-50 shadow-inner">
          <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
          </svg>
        </div>
        <h2 className="text-2xl font-black text-gray-900 tracking-tight">{editedProfile.fullName}</h2>
        <p className="text-xs text-emerald-600 font-black uppercase tracking-widest mt-1">{editedProfile.employmentType}</p>
      </div>

      {/* Security Marker */}
      <div className="bg-gray-900 text-white p-4 rounded-[28px] flex items-center gap-4 shadow-xl">
        <div className="bg-white/20 p-2 rounded-2xl">
          <svg className="w-6 h-6 text-emerald-400" fill="currentColor" viewBox="0 0 20 20">
            <path fillRule="evenodd" d="M2.166 4.999A11.954 11.954 0 0010 1.944 11.954 11.954 0 0017.834 5c.11.65.166 1.32.166 2.001 0 5.225-3.34 9.67-8 11.317C5.34 16.67 2 12.225 2 7c0-.682.057-1.35.166-2.001zm11.541 3.708a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
          </svg>
        </div>
        <div>
          <h4 className="text-xs font-black uppercase tracking-widest text-emerald-400">Privacy Guaranteed</h4>
          <p className="text-[10px] text-gray-400 font-medium">Your financial data is processed with end-to-end encryption. No data is shared with third parties.</p>
        </div>
      </div>

      {/* Account Details */}
      <div className="space-y-4">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] px-2">Account Profile</h3>
        <div className="bg-white rounded-[32px] p-6 shadow-sm border border-gray-100 space-y-5">
          <ProfileInput 
            label="Full Name" 
            value={editedProfile.fullName} 
            onChange={v => setEditedProfile({...editedProfile, fullName: v})} 
          />

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Employment Type</label>
            <select 
              value={editedProfile.employmentType}
              onChange={e => setEditedProfile({ ...editedProfile, employmentType: e.target.value as EmploymentType })}
