          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Industry</label>
            <select 
              value={editedProfile.industry}
              onChange={e => setEditedProfile({ ...editedProfile, industry: e.target.value })}
              className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none text-sm font-bold text-gray-800 appearance-none"
            >
              {industries.map(ind => (
                <option key={ind} value={ind}>{ind}</option>
              ))}
