          </div>

          <ProfileInput 
            label={`Estimated Monthly Income (${CURRENCY})`} 
            type="number" 
            value={editedProfile.monthlyIncome.toString()} 
            onChange={v => setEditedProfile({...editedProfile, monthlyIncome: Number(v)})} 
          />
