            ))}
            {editedProfile.financialGoals.length === 0 && (
              <p className="text-xs text-gray-400 italic px-2">No goals set yet. Add one below!</p>
            )}
          </div>
          <div className="flex gap-2">
            <input 
              type="text"
              placeholder="e.g. Save for Land"
              value={newGoal}
              onChange={(e) => setNewGoal(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && addGoal()}
              className="flex-1 p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none text-sm font-bold text-gray-800 placeholder:text-gray-300"
            />
            <button 
              onClick={addGoal}
              className="bg-emerald-500 text-white p-4 rounded-2xl hover:bg-emerald-600 transition-colors shadow-sm"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
              </svg>
            </button>
          </div>
        </div>
      </div>

      {/* KRA Settings */}
      <div className="space-y-4">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] px-2">KRA & Tax Info</h3>
        <div className="bg-white rounded-[32px] p-6 shadow-sm border border-gray-100">
           <ProfileInput 
             label="KRA PIN" 
             placeholder="A001234567B" 
             value={editedProfile.kraPin || ''} 
             onChange={v => setEditedProfile({...editedProfile, kraPin: v.toUpperCase()})} 
           />
           <p className="text-[10px] text-gray-400 mt-3 font-medium px-1">Your KRA PIN is used to provide accurate tax insights and is stored locally.</p>
        </div>
      </div>

      <button 
        onClick={handleSave}
        className={`w-full py-5 rounded-[28px] font-black uppercase tracking-widest text-sm shadow-xl transition-all active:scale-95 ${isSaved ? 'bg-emerald-100 text-emerald-700 shadow-emerald-50' : 'bg-emerald-600 text-white hover:bg-emerald-700 shadow-emerald-100'}`}
      >
        {isSaved ? '✓ Profile Saved' : 'Update Profile'}
