      <div className="flex justify-center gap-6 py-4">
        <button className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-emerald-600">Privacy Policy</button>
        <button className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-emerald-600">KRA iTax Guide</button>
      </div>
    </div>
  );
};

const ProfileInput: React.FC<{ label: string; value: string; onChange: (v: string) => void; type?: string; placeholder?: string }> = ({ label, value, onChange, type = 'text', placeholder }) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">{label}</label>
    <input 
      type={type} 
      value={value}
      placeholder={placeholder}
      onChange={e => onChange(e.target.value)}
      className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none text-sm font-bold text-gray-800 placeholder:text-gray-300"
    />
  </div>
);

export default Profile;

