  useEffect(() => {
    const mockData: Transaction[] = [
      { id: '1', date: '2023-11-01', merchant: 'Naivas Westlands', amount: 4500, category: Category.FOOD, type: 'expense', source: 'receipt', vatAmount: 720 },
      { id: '2', date: '2023-11-02', merchant: 'Rubis Kileleshwa', amount: 3000, category: Category.TRANSPORT, type: 'expense', source: 'mpesa', vatAmount: 480 },
      { id: '3', date: '2023-11-03', merchant: 'Upwork Payment', amount: 120000, category: Category.OTHER, type: 'income', source: 'manual' },
