import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality } from '@google/genai';
import { Transaction, UserProfile } from '../types';

interface VoiceCoachProps {
  transactions: Transaction[];
  profile?: UserProfile;
}

const VoiceCoach: React.FC<VoiceCoachProps> = ({ transactions, profile }) => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState<'idle' | 'connecting' | 'listening' | 'speaking'>('idle');
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  const startCoaching = async () => {
    setStatus('connecting');
    setIsActive(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('listening');
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;

              const binary = '';
              const bytes = new Uint8Array(int16.buffer);
              let b64 = '';
              for (let i = 0; i < bytes.byteLength; i++) b64 += String.fromCharCode(bytes[i]);

              sessionPromise.then((session) => {
                session.sendRealtimeInput({
                  media: { data: btoa(b64), mimeType: 'audio/pcm;rate=16000' }
                });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (msg) => {
            const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              setStatus('speaking');
              const binaryString = atob(audioData);
              const bytes = new Uint8Array(binaryString.length);
              for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);

              const dataInt16 = new Int16Array(bytes.buffer);
              const buffer = outputCtx.createBuffer(1, dataInt16.length, 24000);
              const channelData = buffer.getChannelData(0);
              for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;

              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);

              const startTime = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              source.start(startTime);
              nextStartTimeRef.current = startTime + buffer.duration;
              source.onended = () => {
                if (outputCtx.currentTime >= nextStartTimeRef.current - 0.1) {
                    setStatus('listening');
                }
              };
            }
          },
          onerror: (e) => {
            console.error('Live API Error:', e);
            setStatus('idle');
          },
          onclose: () => {
            setIsActive(false);
            setStatus('idle');
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: `You are PesaTrack AI Financial Coach. Help the user manage their Kenyan finances. 
          Use Kenyan context (KES, Naivas, M-Pesa). Talk about tax returns, KRA, and budgeting.

          User Profile:
          - Name: ${profile?.fullName || 'Valued User'}
          - Employment: ${profile?.employmentType || 'Unknown'}
          - Industry: ${profile?.industry || 'Unknown'}
          - Goals: ${profile?.financialGoals.join(', ') || 'None set'}

          User recent transactions: ${JSON.stringify(transactions.slice(0, 5))}. 

          Keep responses short, human-like, and encouraging. Greet them by name occasionally.`
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus('idle');
      setIsActive(false);
    }
  };

  const stopCoaching = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
    }
    setIsActive(false);
    setStatus('idle');
  };

  return (
    <div className="flex flex-col items-center justify-center py-10 space-y-8">
      <div className="text-center max-w-xs">
        <h2 className="text-2xl font-black text-gray-800">AI Money Coach</h2>
        <p className="text-gray-500 text-sm mt-2 font-medium">Speak to PesaTrack AI for real-time financial advice tailored to your Kenyan profile.</p>
      </div>

      <div className="relative">
        <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-500 border-8 ${
          status === 'speaking' ? 'border-emerald-700 bg-emerald-50 scale-105 shadow-xl shadow-emerald-100' : 
          status === 'listening' ? 'border-emerald-300 bg-emerald-50 scale-100' : 
          'border-gray-100 bg-white'
        }`}>
          {status === 'speaking' ? (
             <div className="flex gap-1">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="w-1.5 h-8 bg-emerald-700 rounded-full animate-bounce" style={{ animationDelay: `${i * 0.1}s` }}></div>
                ))}
             </div>
          ) : (
            <svg className={`w-20 h-20 ${status === 'listening' ? 'text-emerald-700' : 'text-gray-300'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-6 0V7a3 3 0 013-3z" />
            </svg>
          )}
        </div>

        {status === 'listening' && (
          <div className="absolute inset-0 rounded-full border-4 border-emerald-400 animate-ping opacity-20"></div>
        )}
      </div>

      <div className="text-center">
        <p className="text-emerald-700 font-black mb-4 uppercase tracking-widest text-xs">
          {status === 'connecting' ? 'Connecting to AI...' : status === 'listening' ? 'Listening...' : status === 'speaking' ? 'Coach is talking...' : 'Ready to Talk'}
        </p>

        {!isActive ? (
          <button 
            onClick={startCoaching}
            className="bg-emerald-700 text-white px-10 py-4 rounded-full font-black shadow-xl hover:bg-emerald-800 transition-all active:scale-95 uppercase tracking-widest text-sm"
          >
            Start Conversation
          </button>
        ) : (
          <button 
            onClick={stopCoaching}
            className="bg-black text-white px-10 py-4 rounded-full font-black shadow-md hover:bg-gray-900 transition-all uppercase tracking-widest text-sm"
          >
            End Session
          </button>
        )}
      </div>

      <div className="bg-emerald-50 p-4 rounded-2xl max-w-xs text-center border border-emerald-100">
        <p className="text-[10px] text-emerald-900 font-black uppercase tracking-widest">Try asking:</p>
        <p className="text-xs text-emerald-800 mt-1 italic font-medium">"How can I reduce my PAYE tax this year?" or "Review my spending for last week."</p>
      </div>
    </div>
  );
};

