import React, { useState } from 'react';
import { Transaction, Category } from '../types';
import ReceiptScanner from './ReceiptScanner';
import MpesaInput from './MpesaInput';
import { CURRENCY } from '../constants';

interface AddTransactionProps {
  onAdd: (t: Transaction) => void;
}

const AddTransaction: React.FC<AddTransactionProps> = ({ onAdd }) => {
  const [method, setMethod] = useState<'receipt' | 'mpesa' | 'manual'>('manual');
  const [manualType, setManualType] = useState<'expense' | 'income'>('expense');
  const [formData, setFormData] = useState({
    amount: '',
    merchant: '',
    category: Category.OTHER,
    date: new Date().toISOString().split('T')[0],
  });

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.amount || !formData.merchant) return;

    onAdd({
      id: Math.random().toString(36).substr(2, 9),
      date: formData.date,
      merchant: formData.merchant,
      amount: Number(formData.amount),
      category: formData.category,
      type: manualType,
      source: 'manual',
    });
  };

  return (
    <div className="space-y-6 pb-12">
      {/* Top Method Tabs */}
      <div className="flex bg-gray-200 p-1.5 rounded-[24px] gap-1 shadow-inner">
        <TabBtn active={method === 'manual'} onClick={() => setMethod('manual')} label="Manual" />
        <TabBtn active={method === 'receipt'} onClick={() => setMethod('receipt')} label="Receipt" />
        <TabBtn active={method === 'mpesa'} onClick={() => setMethod('mpesa')} label="M-Pesa" />
      </div>

      {method === 'receipt' && <ReceiptScanner onAdd={onAdd} />}
      {method === 'mpesa' && <MpesaInput onAdd={onAdd} />}

      {method === 'manual' && (
        <div className="bg-white rounded-[40px] p-8 shadow-sm border border-gray-100">
          <div className="flex justify-center mb-8 bg-gray-50 p-1 rounded-2xl border border-gray-100">
            <button 
              onClick={() => setManualType('expense')}
              className={`flex-1 py-3 px-6 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${manualType === 'expense' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-400'}`}
            >
              Cash Expense
            </button>
            <button 
              onClick={() => setManualType('income')}
              className={`flex-1 py-3 px-6 rounded-xl font-black text-xs uppercase tracking-widest transition-all ${manualType === 'income' ? 'bg-emerald-800 text-white shadow-lg' : 'text-gray-400'}`}
            >
              Add Income
            </button>
          </div>

          <form onSubmit={handleManualSubmit} className="space-y-5">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Amount ({CURRENCY})</label>
              <input 
                required
                type="number"
                placeholder="0.00"
                value={formData.amount}
                onChange={e => setFormData({...formData, amount: e.target.value})}
                className="w-full p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none text-xl font-black text-gray-900"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">
                {manualType === 'expense' ? 'Where did you spend?' : 'Income Source'}
              </label>
              <input 
                required
                type="text"
                placeholder={manualType === 'expense' ? 'e.g. Mama Mboga, Kiosk' : 'e.g. Extra Hustle, Gift'}
                value={formData.merchant}
                onChange={e => setFormData({...formData, merchant: e.target.value})}
                className="w-full p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none font-bold text-gray-800"
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Category</label>
              <select 
                value={formData.category}
                onChange={e => setFormData({...formData, category: e.target.value as Category})}
                className="w-full p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none font-bold text-gray-800 appearance-none shadow-sm"
              >
                {Object.values(Category).map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">Date</label>
              <input 
                type="date"
                value={formData.date}
                onChange={e => setFormData({...formData, date: e.target.value})}
                className="w-full p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none font-bold text-gray-800"
              />
            </div>

            <button 
              type="submit"
              className={`w-full py-5 rounded-[28px] font-black uppercase tracking-widest text-sm shadow-xl transition-all active:scale-95 ${manualType === 'expense' ? 'bg-red-600 text-white shadow-red-100 border-b-4 border-black' : 'bg-emerald-800 text-white shadow-emerald-100 border-b-4 border-black'}`}
            >
              {manualType === 'expense' ? 'Record Cash Expense' : 'Save Extra Income'}
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

const TabBtn: React.FC<{ active: boolean; onClick: () => void; label: string }> = ({ active, onClick, label }) => (
  <button 
