];

const Profile: React.FC<ProfileProps> = ({ profile, onSave }) => {
  const [editedProfile, setEditedProfile] = useState<UserProfile>({ 
    ...profile,
    avatar: profile.avatar || 'lion',
    financialGoals: profile.financialGoals || []
  });
