    'Healthcare & Medical',
    'Education & Training',
    'Transport & Logistics',
    'Construction & Real Estate',
    'Retail & Wholesaling',
    'Creative Arts & Entertainment',
    'Hospitality & Tourism',
    'Public Service & Government',
    'Finance & Insurance',
    'Manufacturing',
    'Other'
  ];

  const handleSave = () => {
    onSave(editedProfile);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 3000);
  };

  const addGoal = () => {
    if (newGoal.trim() && !editedProfile.financialGoals.includes(newGoal.trim())) {
      setEditedProfile({
        ...editedProfile,
