      {/* Kenyan Flag Navigation - Sleek Black with Emerald and Red Accents */}
      <nav className="fixed bottom-0 left-0 right-0 bg-black flex justify-around items-center p-3 z-50 rounded-t-[32px] shadow-[0_-4px_20px_rgba(0,0,0,0.3)] border-t-2 border-emerald-800">
