        <div className="relative -top-8">
          <button 
            onClick={() => setActiveTab('add')}
            className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-transform active:scale-90 border-4 border-black ${activeTab === 'add' ? 'bg-red-600 text-white animate-pulse' : 'bg-emerald-700 text-white'}`}
          >
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
