import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Modality, FunctionDeclaration, Type } from '@google/genai';
import { Transaction, UserProfile, Category } from '../types';

interface VoiceCoachProps {
  transactions: Transaction[];
  profile?: UserProfile;
  onAddTransaction: (t: Transaction) => void;
}

const VoiceCoach: React.FC<VoiceCoachProps> = ({ transactions, profile, onAddTransaction }) => {
  const [isActive, setIsActive] = useState(false);
  const [status, setStatus] = useState<'idle' | 'connecting' | 'listening' | 'speaking'>('idle');
  const [lastAdded, setLastAdded] = useState<{ merchant: string, amount: number } | null>(null);
  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);

  const addTransactionFn: FunctionDeclaration = {
    name: 'addTransaction',
    parameters: {
      type: Type.OBJECT,
      description: 'Add a new financial transaction (expense or income) to the user tracker.',
      properties: {
        merchant: { type: Type.STRING, description: 'The merchant or source of income (e.g., Naivas, Upwork, Mama Mboga).' },
        amount: { type: Type.NUMBER, description: 'The amount in KES.' },
        type: { type: Type.STRING, enum: ['expense', 'income'], description: 'Whether this is an expense or income.' },
        category: { 
          type: Type.STRING, 
          enum: Object.values(Category), 
          description: 'The category of the transaction.' 
        },
      },
      required: ['merchant', 'amount', 'type', 'category'],
    },
  };

  const startCoaching = async () => {
    setStatus('connecting');
    setIsActive(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

    try {
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      audioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('listening');
            const source = inputCtx.createMediaStreamSource(stream);
            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const l = inputData.length;
              const int16 = new Int16Array(l);
              for (let i = 0; i < l; i++) int16[i] = inputData[i] * 32768;

              const bytes = new Uint8Array(int16.buffer);
              let b64 = '';
              for (let i = 0; i < bytes.byteLength; i++) b64 += String.fromCharCode(bytes[i]);

              sessionPromise.then((session) => {
                session.sendRealtimeInput({
                  media: { data: btoa(b64), mimeType: 'audio/pcm;rate=16000' }
                });
              });
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);
          },
          onmessage: async (message: any) => {
            // Handle Tool Calls (Voice Transaction)
            if (message.toolCall) {
              for (const fc of message.toolCall.functionCalls) {
                if (fc.name === 'addTransaction') {
                  const args = fc.args as any;
                  const newTransaction: Transaction = {
                    id: Math.random().toString(36).substr(2, 9),
                    date: new Date().toISOString().split('T')[0],
                    merchant: args.merchant,
                    amount: args.amount,
                    category: args.category as Category,
                    type: args.type as 'expense' | 'income',
                    source: 'manual'
                  };
                  onAddTransaction(newTransaction);
                  setLastAdded({ merchant: args.merchant, amount: args.amount });
                  setTimeout(() => setLastAdded(null), 5000);

                  // Respond to the tool call
                  sessionPromise.then((session) => {
                    session.sendToolResponse({
                      functionResponses: [{
                        id: fc.id,
                        name: fc.name,
                        response: { result: "Transaction recorded successfully. You can confirm this with the user." },
                      }]
                    });
                  });
                }
              }
            }

            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              setStatus('speaking');
              const binaryString = atob(audioData);
              const bytes = new Uint8Array(binaryString.length);
              for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);

              const dataInt16 = new Int16Array(bytes.buffer);
              const buffer = outputCtx.createBuffer(1, dataInt16.length, 24000);
              const channelData = buffer.getChannelData(0);
              for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;

              const source = outputCtx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputCtx.destination);

              const startTime = Math.max(nextStartTimeRef.current, outputCtx.currentTime);
              source.start(startTime);
              nextStartTimeRef.current = startTime + buffer.duration;
              source.onended = () => {
                if (outputCtx.currentTime >= nextStartTimeRef.current - 0.1) {
                    setStatus('listening');
                }
              };
            }
          },
          onerror: (e) => {
            console.error('Live API Error:', e);
            setStatus('idle');
          },
          onclose: () => {
            setIsActive(false);
            setStatus('idle');
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          tools: [{ functionDeclarations: [addTransactionFn] }],
          systemInstruction: `You are PesaTrack AI Financial Coach. Help the user manage their Kenyan finances. 
          Use Kenyan context (KES, Naivas, M-Pesa). Talk about tax returns, KRA, and budgeting.

          You can help the user add transactions quickly. If they say something like "I spent 200 on lunch at Mama Mboga", use the addTransaction tool.

          User Profile:
          - Name: ${profile?.fullName || 'Valued User'}
          - Employment: ${profile?.employmentType || 'Unknown'}
          - Industry: ${profile?.industry || 'Unknown'}
          - Goals: ${profile?.financialGoals.join(', ') || 'None set'}

          User recent transactions: ${JSON.stringify(transactions.slice(0, 5))}. 

          Keep responses short, human-like, and encouraging. Greet them by name occasionally.`
        }
      });

      sessionRef.current = await sessionPromise;
    } catch (err) {
      console.error(err);
      setStatus('idle');
      setIsActive(false);
    }
  };

  const stopCoaching = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
    }
    setIsActive(false);
    setStatus('idle');
  };

  return (
    <div className="flex flex-col items-center justify-center py-10 space-y-8 min-h-[60vh]">
      <div className="text-center max-w-xs px-4">
        <h2 className="text-3xl font-black text-black uppercase tracking-tighter">AI Money Coach</h2>
        <p className="text-gray-500 text-xs mt-3 font-bold uppercase tracking-widest leading-relaxed">Add transactions by voice or ask for financial advice.</p>
      </div>

      <div className="relative">
        {/* Transaction Success Toast */}
        {lastAdded && (
          <div className="absolute -top-16 left-1/2 -translate-x-1/2 bg-black text-white px-4 py-2 rounded-2xl shadow-xl flex items-center gap-3 w-max animate-bounce border-2 border-emerald-500">
            <span className="text-xl">✅</span>
            <div className="text-left">
              <p className="text-[10px] font-black uppercase tracking-widest leading-none">Added!</p>
              <p className="text-xs font-bold text-emerald-400">KES {lastAdded.amount} @ {lastAdded.merchant}</p>
            </div>
          </div>
        )}

        <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-500 border-8 ${
          status === 'speaking' ? 'border-red-600 bg-red-50 scale-105 shadow-2xl' : 
          status === 'listening' ? 'border-emerald-700 bg-emerald-50 scale-100 shadow-xl shadow-emerald-100' : 
          'border-black bg-white shadow-inner'
        }`}>
          {status === 'speaking' ? (
             <div className="flex gap-1.5">
                {[...Array(5)].map((_, i) => (
                  <div key={i} className="w-2 h-10 bg-red-600 rounded-full animate-bounce" style={{ animationDelay: `${i * 0.1}s` }}></div>
                ))}
             </div>
          ) : (
            <svg className={`w-20 h-20 ${status === 'listening' ? 'text-emerald-700' : 'text-black'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-6 0V7a3 3 0 013-3z" />
            </svg>
          )}
        </div>

        {status === 'listening' && (
          <div className="absolute inset-0 rounded-full border-4 border-emerald-700 animate-ping opacity-30"></div>
        )}
      </div>

      <div className="text-center w-full px-8">
        <p className="text-black font-black mb-6 uppercase tracking-[0.3em] text-[10px]">
          {status === 'connecting' ? 'Connecting to AI...' : status === 'listening' ? 'I am listening...' : status === 'speaking' ? 'Coach is talking...' : 'Ready to Start'}
        </p>

        {!isActive ? (
          <button 
            onClick={startCoaching}
            className="w-full bg-emerald-800 text-white py-5 rounded-[32px] font-black shadow-2xl hover:bg-emerald-900 transition-all active:scale-95 uppercase tracking-widest text-sm border-b-4 border-black"
          >
            Start Conversation
          </button>
        ) : (
          <button 
            onClick={stopCoaching}
            className="w-full bg-black text-white py-5 rounded-[32px] font-black shadow-md hover:bg-gray-900 transition-all uppercase tracking-widest text-sm border-b-4 border-red-600"
          >
            Stop
          </button>
        )}
      </div>

      <div className="bg-emerald-50 p-6 rounded-[32px] max-w-xs text-center border-2 border-emerald-700 mx-4">
        <p className="text-[10px] text-emerald-900 font-black uppercase tracking-widest mb-2">Voice Shortcuts:</p>
        <p className="text-xs text-emerald-800 font-bold italic leading-relaxed">"I just spent 50 shillings on Boda Boda" or "I received 5000 from a gig"</p>
      </div>
    </div>
  );
};

export default VoiceCoach;

import React, { useState, useEffect } from 'react';
import { Transaction, Category, UserProfile, EmploymentType } from './types';
import Dashboard from './components/Dashboard';
import AddTransaction from './components/AddTransaction';
import TaxEngine from './components/TaxEngine';
import VoiceCoach from './components/VoiceCoach';
import Profile from './components/Profile';
import Goals from './components/Goals';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'add' | 'tax' | 'coach' | 'goals' | 'profile'>('home');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('pesatrack_profile');
    return saved ? JSON.parse(saved) : {
      fullName: 'Kevin Omari',
      employmentType: EmploymentType.FREELANCER,
      monthlyIncome: 85000,
      industry: 'Technology & Digital Services',
      financialGoals: ['Buying Land in Kajiado', 'Emergency Fund'],
      avatar: 'lion'
    };
  });

  useEffect(() => {
    localStorage.setItem('pesatrack_profile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    const mockData: Transaction[] = [
      { id: '1', date: '2024-03-01', merchant: 'Naivas Westlands', amount: 4500, category: Category.FOOD, type: 'expense', source: 'receipt', vatAmount: 720 },
      { id: '2', date: '2024-03-02', merchant: 'Rubis Kileleshwa', amount: 3000, category: Category.TRANSPORT, type: 'expense', source: 'mpesa', vatAmount: 480 },
      { id: '3', date: '2024-03-03', merchant: 'Upwork Payment', amount: 120000, category: Category.OTHER, type: 'income', source: 'manual' },
      { id: '4', date: '2024-03-04', merchant: 'KPLC Prepaid', amount: 2000, category: Category.UTILITIES, type: 'expense', source: 'mpesa' },
    ];
    setTransactions(mockData);
  }, []);

  const addTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
  };

  const handleUpdateGoals = (newGoals: string[]) => {
    setProfile(prev => ({ ...prev, financialGoals: newGoals }));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <Dashboard transactions={transactions} profile={profile} onNavigate={setActiveTab} />;
      case 'add': return <AddTransaction onAdd={(t) => { addTransaction(t); setActiveTab('home'); }} />;
      case 'tax': return <TaxEngine transactions={transactions} profile={profile} />;
      case 'coach': return <VoiceCoach transactions={transactions} profile={profile} onAddTransaction={addTransaction} />;
      case 'profile': return <Profile profile={profile} onSave={setProfile} />;
      case 'goals': return <Goals transactions={transactions} profile={profile} onUpdateGoals={handleUpdateGoals} />;
      default: return <Dashboard transactions={transactions} profile={profile} onNavigate={setActiveTab} />;
    }
  };

  const getAvatarEmoji = (id?: string) => {
    const avatars: Record<string, string> = {
      lion: '🦁',
      runner: '🏃🏾‍♂️',
      maasai: '🛡️',
      coffee: '☕',
      elephant: '🐘',
      tea: '🍃',
      landscape: '🏔️',
      truck: '🚛',
    };
    return avatars[id || 'lion'] || '🦁';
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col pb-24 selection:bg-emerald-200">
      {/* Kenyan Flag Header - Deep Emerald Green with Red Detail */}
      <header className="bg-emerald-800 text-white pt-6 pb-4 px-6 shadow-md sticky top-0 z-50 border-b-4 border-red-600">
        <div className="max-w-md mx-auto flex justify-between items-end">
          <div>
            <p className="text-emerald-100 text-[10px] font-black uppercase tracking-widest mb-1">PesaTrack AI 🇰🇪</p>
            <h1 className="text-2xl font-black tracking-tighter uppercase">{profile.fullName.split(' ')[0]}</h1>
          </div>
          <button 
            onClick={() => setActiveTab('profile')}
            className="relative group focus:outline-none"
            aria-label="Profile Settings"
          >
            <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all text-2xl ${activeTab === 'profile' ? 'bg-red-600 text-white scale-110 shadow-lg' : 'bg-black text-white hover:bg-emerald-700'}`}>
              {getAvatarEmoji(profile.avatar)}
            </div>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-md mx-auto p-4 md:p-6">
        {renderContent()}
      </main>

      {/* Kenyan Flag Navigation - Replace Profile with Goals */}
      <nav className="fixed bottom-0 left-0 right-0 bg-black flex justify-around items-center p-3 z-50 rounded-t-[32px] shadow-[0_-4px_20px_rgba(0,0,0,0.3)] border-t-2 border-emerald-800">
        <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon="home" label="Home" />
        <NavButton active={activeTab === 'tax'} onClick={() => setActiveTab('tax')} icon="tax" label="Tax" />

        <div className="relative -top-8">
          <button 
            onClick={() => setActiveTab('add')}
            className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-transform active:scale-90 border-4 border-black ${activeTab === 'add' ? 'bg-red-600 text-white' : 'bg-emerald-700 text-white'}`}
          >
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
            </svg>
          </button>
          <span className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-black uppercase text-emerald-500 tracking-tighter">Add</span>
        </div>

        <NavButton active={activeTab === 'coach'} onClick={() => setActiveTab('coach')} icon="voice" label="Coach" />
        <NavButton active={activeTab === 'goals'} onClick={() => setActiveTab('goals')} icon="goals" label="Goals" />
      </nav>
    </div>
  );
};

