import React, { useState } from 'react';
import { Transaction, UserProfile } from '../types';
import { CURRENCY } from '../constants';

interface GoalsProps {
  transactions: Transaction[];
  profile: UserProfile;
  onUpdateGoals: (goals: string[]) => void;
}

const Goals: React.FC<GoalsProps> = ({ transactions, profile, onUpdateGoals }) => {
  const [newGoal, setNewGoal] = useState('');

  // Calculate some mock savings data based on profile
  const totalIncome = transactions
    .filter(t => t.type === 'income')
    .reduce((sum, t) => sum + t.amount, 0);

  const totalExpenses = transactions
    .filter(t => t.type === 'expense')
    .reduce((sum, t) => sum + t.amount, 0);

  const potentialSavings = Math.max(0, totalIncome - totalExpenses);

  const addGoal = () => {
    if (newGoal.trim() && !profile.financialGoals.includes(newGoal.trim())) {
      onUpdateGoals([...profile.financialGoals, newGoal.trim()]);
      setNewGoal('');
    }
  };

  const removeGoal = (goal: string) => {
    onUpdateGoals(profile.financialGoals.filter(g => g !== goal));
  };

  return (
    <div className="space-y-6 pb-12">
      {/* Savings Summary Hero */}
      <div className="bg-emerald-800 rounded-[40px] p-8 shadow-2xl relative overflow-hidden text-white border-b-4 border-red-600">
        <div className="relative z-10">
          <p className="text-emerald-100 text-[10px] font-black uppercase tracking-[0.2em] mb-3 text-center">Current Savings Pool</p>
          <h2 className="text-4xl font-black text-center tracking-tighter mb-4">
            {CURRENCY} <span className="text-emerald-400">{potentialSavings.toLocaleString()}</span>
          </h2>
          <div className="flex justify-between items-center bg-black/20 p-4 rounded-2xl backdrop-blur-sm">
            <div className="text-center flex-1 border-r border-white/10">
              <p className="text-[8px] font-black uppercase text-emerald-300">Monthly Target</p>
              <p className="text-sm font-black">{CURRENCY} {(profile.monthlyIncome * 0.2).toLocaleString()}</p>
            </div>
            <div className="text-center flex-1">
              <p className="text-[8px] font-black uppercase text-red-300">Daily Average</p>
              <p className="text-sm font-black">{CURRENCY} {(potentialSavings / 30).toFixed(0)}</p>
            </div>
          </div>
        </div>
        {/* Flag Stripe Design */}
        <div className="absolute top-0 right-0 w-2 h-full bg-red-600"></div>
        <div className="absolute top-0 right-2 w-1 h-full bg-white opacity-20"></div>
      </div>

      {/* Goal Management Section */}
      <section className="space-y-4">
        <div className="flex justify-between items-end px-2">
          <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">Wealth Milestones</h3>
          <span className="text-[10px] font-black text-emerald-800 bg-emerald-50 px-2 py-1 rounded-full">{profile.financialGoals.length} Active</span>
        </div>

        <div className="bg-white rounded-[32px] p-6 shadow-sm border border-gray-100 space-y-6">
          <div className="space-y-4">
            {profile.financialGoals.map((goal, index) => (
              <GoalCard 
                key={index} 
                title={goal} 
                onRemove={() => removeGoal(goal)} 
                progress={Math.min(100, Math.floor(Math.random() * 60) + 10)} 
              />
            ))}

            {profile.financialGoals.length === 0 && (
              <div className="py-12 text-center border-2 border-dashed border-gray-100 rounded-3xl">
                <p className="text-sm text-gray-400 font-bold">No active goals yet.</p>
                <p className="text-[10px] text-gray-300 uppercase tracking-widest mt-1">Start your journey to prosperity</p>
              </div>
            )}
          </div>

          <div className="flex gap-2">
            <input 
              type="text"
              placeholder="Add new goal (e.g. Save for Cow)"
              value={newGoal}
              onChange={(e) => setNewGoal(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && addGoal()}
              className="flex-1 p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-800 outline-none text-sm font-bold text-gray-800 placeholder:text-gray-300"
            />
            <button 
              onClick={addGoal}
              className="bg-black text-white p-4 rounded-2xl hover:bg-emerald-900 transition-all shadow-lg active:scale-95"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
              </svg>
            </button>
          </div>
        </div>
      </section>

      {/* Saving Tips */}
      <div className="bg-red-50 p-6 rounded-[32px] border border-red-100">
        <div className="flex gap-4 items-start">
          <div className="w-10 h-10 bg-white rounded-2xl flex items-center justify-center text-xl shadow-sm">💡</div>
          <div>
            <h4 className="text-xs font-black text-red-900 uppercase tracking-widest mb-1">Coach Tip</h4>
            <p className="text-[11px] text-red-800 leading-relaxed">
              "You usually spend 15% more on weekends. Try setting aside 500 KES every Friday to hit your goal 2 months faster!"
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

const GoalCard: React.FC<{ title: string; onRemove: () => void; progress: number }> = ({ title, onRemove, progress }) => {
  return (
    <div className="bg-gray-50 p-5 rounded-3xl border border-gray-100 group transition-all hover:border-emerald-500 hover:shadow-md">
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-emerald-800 rounded-xl flex items-center justify-center text-xs text-white font-black">🇰🇪</div>
          <p className="text-sm font-black text-gray-900">{title}</p>
        </div>
