import React, { useState, useEffect } from 'react';
import { Transaction, Category, UserProfile, EmploymentType } from './types';
import Dashboard from './components/Dashboard';
import AddTransaction from './components/AddTransaction';
import TaxEngine from './components/TaxEngine';
import VoiceCoach from './components/VoiceCoach';
import Profile from './components/Profile';
import Goals from './components/Goals';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'add' | 'tax' | 'coach' | 'goals' | 'profile'>('home');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('pesatrack_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('pesatrack_profile');
    return saved ? JSON.parse(saved) : {
      fullName: '',
      employmentType: EmploymentType.OTHER,
      monthlyIncome: 0,
      industry: 'Other',
      financialGoals: [],
      avatar: 'lion'
    };
  });

  useEffect(() => {
    localStorage.setItem('pesatrack_profile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('pesatrack_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
  };

  const handleUpdateGoals = (newGoals: string[]) => {
    setProfile(prev => ({ ...prev, financialGoals: newGoals }));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <Dashboard transactions={transactions} profile={profile} onNavigate={setActiveTab} />;
      case 'add': return <AddTransaction onAdd={(t) => { addTransaction(t); setActiveTab('home'); }} />;
      case 'tax': return <TaxEngine transactions={transactions} profile={profile} />;
      case 'coach': return <VoiceCoach transactions={transactions} profile={profile} onAddTransaction={addTransaction} />;
      case 'profile': return <Profile profile={profile} onSave={setProfile} />;
      case 'goals': return <Goals transactions={transactions} profile={profile} onUpdateGoals={handleUpdateGoals} />;
      default: return <Dashboard transactions={transactions} profile={profile} onNavigate={setActiveTab} />;
    }
  };

  const getAvatarEmoji = (id?: string) => {
    const avatars: Record<string, string> = {
      lion: '🦁',
      runner: '🏃🏾‍♂️',
      maasai: '🛡️',
      coffee: '☕',
      elephant: '🐘',
      tea: '🍃',
      landscape: '🏔️',
      truck: '🚛',
    };
    return avatars[id || 'lion'] || '🦁';
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col pb-24 selection:bg-emerald-200 transition-all">
      {/* Kenyan Flag Header - Responsive width */}
      <header className="bg-emerald-800 text-white pt-6 pb-4 px-6 shadow-md sticky top-0 z-50 border-b-4 border-red-600">
        <div className="max-w-4xl mx-auto flex justify-between items-end">
          <div className="flex-1">
            <p className="text-emerald-100 text-[10px] font-black uppercase tracking-widest mb-1">PesaTrack AI 🇰🇪</p>
            <h1 className="text-2xl font-black tracking-tighter uppercase truncate max-w-[200px] sm:max-w-none">
              {profile.fullName ? profile.fullName.split(' ')[0] : 'Citizen'}
            </h1>
          </div>
          <button 
            onClick={() => setActiveTab('profile')}
            className="relative group focus:outline-none flex-shrink-0"
            aria-label="Profile Settings"
          >
            <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all text-2xl ${activeTab === 'profile' ? 'bg-red-600 text-white scale-110 shadow-lg' : 'bg-black text-white hover:bg-emerald-700'}`}>
              {getAvatarEmoji(profile.avatar)}
            </div>
          </button>
        </div>
      </header>

      {/* Main Content - Expanded for responsiveness */}
      <main className="flex-1 w-full max-w-4xl mx-auto p-4 md:p-8">
        {renderContent()}
      </main>

      {/* Kenyan Flag Navigation - Responsive centering */}
      <nav className="fixed bottom-0 left-0 right-0 bg-black flex justify-center items-center p-3 z-50 rounded-t-[32px] shadow-[0_-4px_20px_rgba(0,0,0,0.3)] border-t-2 border-emerald-800">
        <div className="flex justify-around items-center w-full max-w-lg">
          <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon="home" label="Home" />
          <NavButton active={activeTab === 'tax'} onClick={() => setActiveTab('tax')} icon="tax" label="Tax" />

          <div className="relative -top-8">
            <button 
              onClick={() => setActiveTab('add')}
              className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-transform active:scale-90 border-4 border-black ${activeTab === 'add' ? 'bg-red-600 text-white' : 'bg-emerald-700 text-white'}`}
            >
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
              </svg>
            </button>
            <span className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-black uppercase text-emerald-500 tracking-tighter">Add</span>
          </div>

          <NavButton active={activeTab === 'coach'} onClick={() => setActiveTab('coach')} icon="voice" label="Coach" />
          <NavButton active={activeTab === 'goals'} onClick={() => setActiveTab('goals')} icon="goals" label="Goals" />
        </div>
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
