import React, { useMemo } from 'react';
import { Transaction, Category, UserProfile, EmploymentType } from '../types';
import { KENYA_TAX_BANDS, CURRENCY } from '../constants';

interface TaxEngineProps {
  transactions: Transaction[];
  profile: UserProfile;
}

const TaxEngine: React.FC<TaxEngineProps> = ({ transactions, profile }) => {
  const stats = useMemo(() => {
    const transactionsIncome = transactions
      .filter(t => t.type === 'income')
      .reduce((sum, t) => sum + t.amount, 0);

    const yearlyIncome = transactionsIncome || (profile.monthlyIncome * 12);

    const deductibleExpenses = transactions
      .filter(t => t.isBusiness || t.category === Category.BUSINESS)
      .reduce((sum, t) => sum + t.amount, 0);

    const taxableIncome = Math.max(0, yearlyIncome - deductibleExpenses);

    let taxLiability = 0;
    let remainingIncome = taxableIncome;
    let prevBand = 0;

    for (const band of KENYA_TAX_BANDS) {
      const currentBandLimit = band.upTo === Infinity ? remainingIncome : band.upTo - prevBand;
      const taxableInBand = Math.min(remainingIncome, currentBandLimit);
      taxLiability += taxableInBand * band.rate;
      remainingIncome -= taxableInBand;
      prevBand = band.upTo;
      if (remainingIncome <= 0) break;
    }

    const personalRelief = 2400 * 12; 
    const estimatedTax = Math.max(0, taxLiability - personalRelief);

    return {
      yearlyIncome,
      deductibleExpenses,
      estimatedTax,
      refundProbability: transactions.length > 0 ? 82 : 0,
      estimatedRefund: Math.max(0, deductibleExpenses * 0.16)
    };
  }, [transactions, profile]);

  return (
    <div className="space-y-6 md:space-y-8">
      {/* Refund Hero Card - Kenyan Flag Red */}
      <div className="bg-red-600 text-white rounded-[40px] p-8 md:p-12 shadow-2xl shadow-red-200 relative overflow-hidden">
        <div className="relative z-10 max-w-xl mx-auto text-center">
          <p className="text-red-100 text-xs font-bold uppercase tracking-widest mb-2">Potential Tax Savings & Refunds</p>
          <h2 className="text-4xl md:text-5xl font-black mb-8">{CURRENCY} {stats.estimatedRefund.toLocaleString()}</h2>

          <div className="flex justify-between items-center mb-3">
            <span className="text-xs font-bold uppercase tracking-widest">Audit Quality Score</span>
            <span className="text-lg font-black">{stats.refundProbability}%</span>
          </div>
          <div className="w-full h-3 bg-red-800 rounded-full overflow-hidden">
            <div 
              style={{ width: `${stats.refundProbability}%` }}
              className="h-full bg-white rounded-full shadow-lg transition-all duration-1000"
            ></div>
          </div>
          <p className="text-[10px] text-red-100/70 mt-4 font-medium italic">
            {transactions.length === 0 
              ? "Scan business receipts to calculate your tax-deductible expenses."
              : "Keep scanning eTIMS receipts to maximize your VAT and income tax claims."}
          </p>
        </div>
        {/* Decorator Circles */}
        <div className="absolute top-[-20px] right-[-20px] w-32 h-32 bg-white/10 rounded-full"></div>
        <div className="absolute bottom-[-40px] left-[-20px] w-48 h-48 bg-red-500 rounded-full blur-2xl"></div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-white p-6 rounded-[32px] border border-gray-100 shadow-sm flex flex-col justify-center">
          <p className="text-gray-400 text-[10px] font-bold uppercase tracking-wider mb-2">Annual PAYE Liability</p>
          <p className="text-xl md:text-2xl font-black text-gray-800">{CURRENCY} {stats.estimatedTax.toLocaleString()}</p>
        </div>
        <div className="bg-white p-6 rounded-[32px] border border-gray-100 shadow-sm flex flex-col justify-center">
          <p className="text-gray-400 text-[10px] font-bold uppercase tracking-wider mb-2">Total Deductible (Hustle/Biz)</p>
          <p className="text-xl md:text-2xl font-black text-emerald-700">{CURRENCY} {stats.deductibleExpenses.toLocaleString()}</p>
        </div>
      </div>

      <div className="bg-white p-8 rounded-[32px] shadow-sm border border-gray-100">
        <h3 className="font-black text-gray-800 mb-8 uppercase tracking-tight text-sm">iTax Optimization Checklist</h3>
        <ul className="grid grid-cols-1 md:grid-cols-2 gap-x-10 gap-y-8">
          <StrategyItem 
            title="Insurance Relief" 
            desc="NHIF/SHIF and Life Insurance premiums qualify for 15% tax relief."
            status="missing"
          />
          <StrategyItem 
            title="Mortgage Interest" 
            desc="Claim up to KES 300,000 annually against your taxable income."
            status="available"
          />
          <StrategyItem 
            title="VAT Claim" 
            desc="Every business eTIMS receipt is a potential cash-back for your SME."
            status="action"
          />
          <StrategyItem 
            title="Pension Shield" 
            desc="Contributions to NSSF and approved schemes are tax-free up to 20k/mo."
            status="available"
          />
        </ul>
      </div>

      <div className="max-w-md mx-auto w-full">
        <button className="w-full bg-black text-white py-5 rounded-[28px] font-black uppercase tracking-widest text-sm hover:bg-gray-900 transition-all active:scale-95 shadow-xl shadow-gray-200">
          Prepare 2024 Return Preview
        </button>
      </div>

      <p className="text-[10px] text-center text-gray-400 px-8 font-medium italic pb-8">
        * Estimates based on current Kenyan Tax Laws (FA 2023/24). PesaTrack is an assistant, not a KRA agent.
      </p>
    </div>
