                  onChange={e => setEditedProfile({ ...editedProfile, employmentType: e.target.value as EmploymentType })}
                  className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-800 outline-none text-sm font-bold text-gray-800 appearance-none shadow-sm"
                >
                  {Object.values(EmploymentType).map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>
            </div>

            <ProfileInput 
              label={`Base Monthly Income (${CURRENCY})`} 
              type="number" 
              value={editedProfile.monthlyIncome ? editedProfile.monthlyIncome.toString() : ''} 
              onChange={v => setEditedProfile({...editedProfile, monthlyIncome: Number(v)})} 
              placeholder="0"
            />
          </div>
        </section>
      </div>

      {/* KRA Compliance - Single Column but wider on Desktop */}
      <section className="space-y-4">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em] px-2">Tax Registration</h3>
        <div className="bg-white rounded-[32px] p-8 shadow-sm border border-gray-100">
           <ProfileInput 
             label="Personal KRA PIN" 
             placeholder="A001234567B" 
             value={editedProfile.kraPin || ''} 
             onChange={v => setEditedProfile({...editedProfile, kraPin: v.toUpperCase()})} 
           />
           <div className="flex gap-4 mt-6 bg-emerald-50 p-6 rounded-2xl border border-emerald-100 items-center">
             <div className="bg-emerald-100 text-emerald-800 p-3 rounded-full shrink-0">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 00-2 2z" />
               </svg>
             </div>
             <p className="text-xs text-emerald-800 font-medium leading-relaxed italic">
               Your KRA PIN is stored securely on your device. We use it to ensure you never miss legal tax reliefs available to Kenyan citizens.
             </p>
           </div>
        </div>
      </section>

      {/* Action Buttons - Centered */}
      <div className="max-w-md mx-auto w-full px-2 space-y-4">
        <button 
          onClick={handleSave}
          className={`w-full py-5 rounded-[28px] font-black uppercase tracking-widest text-sm shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${
            isSaved 
              ? 'bg-emerald-100 text-emerald-800 border-2 border-emerald-500' 
              : 'bg-emerald-800 text-white hover:bg-emerald-900 shadow-emerald-200 border-b-4 border-black'
          }`}
        >
          {isSaved ? (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
              Citizen Profile Saved
            </>
          ) : 'Save My Kenyan Profile'}
        </button>

        <div className="flex justify-between items-center px-4 py-2">
          <button className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-red-600 transition-colors">Clear All Data</button>
          <button className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-emerald-800 transition-colors">Privacy Shield</button>
        </div>
      </div>
    </div>
  );
};

const ProfileInput: React.FC<{ label: string; value: string; onChange: (v: string) => void; type?: string; placeholder?: string }> = ({ label, value, onChange, type = 'text', placeholder }) => (
  <div className="space-y-2">
    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">{label}</label>
    <input 
      type={type} 
      value={value}
      placeholder={placeholder}
      onChange={e => onChange(e.target.value)}
      className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-emerald-800 outline-none text-sm font-bold text-gray-800 placeholder:text-gray-300 shadow-sm transition-all"
    />
  </div>
);

export default Profile;

import React, { useState, useEffect } from 'react';
import { Transaction, Category, UserProfile, EmploymentType } from './types';
import Dashboard from './components/Dashboard';
import AddTransaction from './components/AddTransaction';
import TaxEngine from './components/TaxEngine';
import VoiceCoach from './components/VoiceCoach';
import Profile from './components/Profile';
import Goals from './components/Goals';
import { TRANSLATIONS } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'add' | 'tax' | 'coach' | 'goals' | 'profile'>('home');
  const [lang, setLang] = useState<'en' | 'sw'>('en');
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('pesatrack_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('pesatrack_profile');
    return saved ? JSON.parse(saved) : {
      fullName: '',
      employmentType: EmploymentType.OTHER,
      monthlyIncome: 0,
      industry: 'Other',
      financialGoals: [],
      avatar: 'lion'
    };
  });

  const t = TRANSLATIONS[lang];

  useEffect(() => {
    localStorage.setItem('pesatrack_profile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('pesatrack_transactions', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (t: Transaction) => {
    setTransactions(prev => [t, ...prev]);
  };

  const handleUpdateGoals = (newGoals: string[]) => {
    setProfile(prev => ({ ...prev, financialGoals: newGoals }));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <Dashboard transactions={transactions} profile={profile} onNavigate={setActiveTab} lang={lang} />;
      case 'add': return <AddTransaction onAdd={(t) => { addTransaction(t); setActiveTab('home'); }} lang={lang} />;
      case 'tax': return <TaxEngine transactions={transactions} profile={profile} lang={lang} />;
      case 'coach': return <VoiceCoach transactions={transactions} profile={profile} onAddTransaction={addTransaction} />;
      case 'profile': return <Profile profile={profile} onSave={setProfile} lang={lang} onLangToggle={(l) => setLang(l)} />;
      case 'goals': return <Goals transactions={transactions} profile={profile} onUpdateGoals={handleUpdateGoals} lang={lang} />;
      default: return <Dashboard transactions={transactions} profile={profile} onNavigate={setActiveTab} lang={lang} />;
    }
  };

  const getAvatarEmoji = (id?: string) => {
    const avatars: Record<string, string> = {
      lion: '🦁', runner: '🏃🏾‍♂️', maasai: '🛡️', coffee: '☕',
      elephant: '🐘', tea: '🍃', landscape: '🏔️', truck: '🚛',
    };
    return avatars[id || 'lion'] || '🦁';
  };

  return (
    <div className="min-h-screen bg-[#F8F9FA] flex flex-col pb-24 selection:bg-emerald-200 transition-all">
      {/* Kenyan Flag Header */}
      <header className="bg-emerald-800 text-white pt-6 pb-4 px-6 shadow-md sticky top-0 z-50 border-b-4 border-red-600">
        <div className="max-w-4xl mx-auto flex justify-between items-end">
          <div className="flex-1">
            <p className="text-emerald-100 text-[10px] font-black uppercase tracking-widest mb-1">PesaTrack AI 🇰🇪</p>
            <h1 className="text-2xl font-black tracking-tighter uppercase truncate max-w-[200px] sm:max-w-none">
              {profile.fullName ? profile.fullName.split(' ')[0] : t.citizen}
            </h1>
          </div>
          <button 
            onClick={() => setActiveTab('profile')}
            className="relative group focus:outline-none flex-shrink-0"
            aria-label="Profile Settings"
          >
            <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all text-2xl ${activeTab === 'profile' ? 'bg-red-600 text-white scale-110 shadow-lg' : 'bg-black text-white hover:bg-emerald-700'}`}>
              {getAvatarEmoji(profile.avatar)}
            </div>
          </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 w-full max-w-4xl mx-auto p-4 md:p-8">
        {renderContent()}
      </main>

      {/* Fixed Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-black flex justify-center items-center p-3 z-50 rounded-t-[32px] shadow-[0_-4px_20px_rgba(0,0,0,0.3)] border-t-2 border-emerald-800">
        <div className="flex justify-around items-center w-full max-w-lg">
          <NavButton active={activeTab === 'home'} onClick={() => setActiveTab('home')} icon="home" label={t.home} />
          <NavButton active={activeTab === 'tax'} onClick={() => setActiveTab('tax')} icon="tax" label={t.tax} />

          <div className="relative -top-8">
            <button 
              onClick={() => setActiveTab('add')}
              className={`w-16 h-16 rounded-full flex items-center justify-center shadow-2xl transition-transform active:scale-90 border-4 border-black ${activeTab === 'add' ? 'bg-red-600 text-white animate-pulse' : 'bg-emerald-700 text-white'}`}
            >
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" />
              </svg>
            </button>
            <span className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] font-black uppercase text-emerald-500 tracking-tighter">{t.add}</span>
          </div>

          <NavButton active={activeTab === 'coach'} onClick={() => setActiveTab('coach')} icon="voice" label={t.coach} />
          <NavButton active={activeTab === 'goals'} onClick={() => setActiveTab('goals')} icon="goals" label={t.goals} />
        </div>
      </nav>
    </div>
  );
};

interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: 'home' | 'tax' | 'voice' | 'goals';
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => {
  const iconMap = {
    home: <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />,
    tax: <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />,
    voice: <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-6 0V7a3 3 0 013-3z" />,
    goals: <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
  };

  return (
    <button onClick={onClick} className={`flex flex-col items-center gap-1 transition-all ${active ? 'text-red-500' : 'text-emerald-100 hover:text-emerald-400'}`}>
      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        {iconMap[icon]}
      </svg>
      <span className="text-[10px] font-black uppercase tracking-tight">{label}</span>
    </button>
  );
};

export default App;

import React from 'react';
