                  <h4 className="font-black text-gray-900 text-lg leading-tight uppercase tracking-tight">{topCategory.name}</h4>
                  <p className="text-emerald-700 font-black text-sm">{CURRENCY} {topCategory.value.toLocaleString()}</p>
