}

const Dashboard: React.FC<DashboardProps> = ({ transactions, profile, budgets = [], onNavigate, lang }) => {
  const t = TRANSLATIONS[lang];

  const currentMonthExpenses = transactions
    .filter(tr => tr.type === 'expense' && new Date(tr.date).getMonth() === new Date().getMonth())
    .reduce((sum, tr) => sum + tr.amount, 0);

  const categoryTotals = Object.values(Category).map(cat => ({
    name: cat,
    value: transactions
      .filter(tr => tr.category === cat && tr.type === 'expense')
      .reduce((sum, tr) => sum + tr.amount, 0)
  })).sort((a, b) => b.value - a.value);

  const topCategory = categoryTotals[0];
  const refundPotential = currentMonthExpenses * 0.16 * 0.25;

  // Budget calculations
  const budgetSummary = budgets.filter(b => b.monthlyLimit > 0).map(b => {
    const spentThisMonth = transactions
      .filter(t => t.category === b.category && t.type === 'expense' && new Date(t.date).getMonth() === new Date().getMonth())
      .reduce((sum, t) => sum + t.amount, 0);
    return {
      category: b.category,
      spent: spentThisMonth,
      limit: b.monthlyLimit,
      progress: Math.min(100, (spentThisMonth / b.monthlyLimit) * 100)
    };
  }).filter(b => b.limit > 0).slice(0, 3);

  return (
    <div className="space-y-6 lg:space-y-10 animate-in fade-in duration-500">
