import { encryptData, decryptData } from './utils/security';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'home' | 'add' | 'tax' | 'coach' | 'analysis' | 'profile' | 'goals'>('home');
  const [lang, setLang] = useState<'en' | 'sw'>('en');
