  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('akiba_pr_secure');
    return saved ? (decryptData(saved) || {
      fullName: '',
      employmentType: EmploymentType.OTHER,
      monthlyIncome: 0,
      industry: 'Other',
      financialGoals: [],
      avatar: 'lion',
      isPasswordEnabled: false
