import { Transaction, Category, Budget } from '../types';
import { CURRENCY } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend } from 'recharts';

interface FinancialAnalysisProps {
  transactions: Transaction[];
  budgets: Budget[];
  onUpdateBudgets: (budgets: Budget[]) => void;
  onUpdateTransaction: (transaction: Transaction) => void;
  onDeleteTransaction: (id: string) => void;
  lang: 'en' | 'sw';
}

const FinancialAnalysis: React.FC<FinancialAnalysisProps> = ({ transactions, budgets, onUpdateBudgets, onUpdateTransaction, onDeleteTransaction, lang }) => {
  const [activeView, setActiveView] = useState<'logs' | 'analysis' | 'budget'>('analysis');
  const [budgetPeriod, setBudgetPeriod] = useState<'weekly' | 'monthly'>('weekly');
  const [search, setSearch] = useState('');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const now = new Date();
  const currentMonth = now.getMonth();

  // Financial Metrics
  const monthlyIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === currentMonth)
    .reduce((sum, t) => sum + t.amount, 0);

  const monthlyExpense = transactions
    .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === currentMonth)
    .reduce((sum, t) => sum + t.amount, 0);

  const netFlow = monthlyIncome - monthlyExpense;
  const flowRatio = monthlyIncome > 0 ? (monthlyExpense / monthlyIncome) * 100 : 0;

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => 
      t.merchant.toLowerCase().includes(search.toLowerCase()) || 
      t.category.toLowerCase().includes(search.toLowerCase())
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, search]);

  const categoryData = useMemo(() => {
    const data: Record<string, number> = {};
    transactions.filter(t => t.type === 'expense' && new Date(t.date).getMonth() === currentMonth).forEach(t => {
      data[t.category] = (data[t.category] || 0) + t.amount;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [transactions, currentMonth]);

  const COLORS = ['#10b981', '#ef4444', '#065f46', '#f59e0b', '#3b82f6', '#8b5cf6', '#ec4899', '#6b7280'];

  const handleEditSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTransaction) {
      onUpdateTransaction(editingTransaction);
      setEditingTransaction(null);
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500">
      <div className="flex bg-gray-200 p-1.5 rounded-[28px] sm:rounded-[36px] gap-1 shadow-inner max-w-md mx-auto">
        <button onClick={() => setActiveView('analysis')} className={`flex-1 py-3 rounded-[22px] font-black text-[10px] uppercase tracking-widest transition-all ${activeView === 'analysis' ? 'bg-white text-black shadow-md' : 'text-gray-400'}`}>Analysis</button>
        <button onClick={() => setActiveView('logs')} className={`flex-1 py-3 rounded-[22px] font-black text-[10px] uppercase tracking-widest transition-all ${activeView === 'logs' ? 'bg-white text-black shadow-md' : 'text-gray-400'}`}>Logs</button>
        <button onClick={() => setActiveView('budget')} className={`flex-1 py-3 rounded-[22px] font-black text-[10px] uppercase tracking-widest transition-all ${activeView === 'budget' ? 'bg-white text-black shadow-md' : 'text-gray-400'}`}>Budgets</button>
      </div>

      {activeView === 'analysis' && (
        <div className="space-y-8">
          <section className="bg-[#0A0D10] text-white rounded-[40px] p-8 border border-emerald-900/50 relative overflow-hidden">
            <div className="relative z-10 grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="space-y-2">
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-[0.2em]">CASH FLOW</p>
                <h4 className="text-3xl font-black">{CURRENCY} {netFlow.toLocaleString()}</h4>
              </div>
              <div className="space-y-2">
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-[0.2em]">BURN RATE</p>
                <h4 className="text-3xl font-black">{flowRatio.toFixed(1)}%</h4>
              </div>
              <div className="space-y-2">
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-[0.2em]">INCOME</p>
                <h4 className="text-3xl font-black">{CURRENCY} {monthlyIncome.toLocaleString()}</h4>
              </div>
            </div>
          </section>

          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6">Spending Breakdown</h3>
            <div className="h-[300px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                    {categoryData.map((_, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                  </Pie>
                  <Tooltip />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      )}

      {activeView === 'logs' && (
        <div className="space-y-4">
          <input type="text" placeholder="Search..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full p-4 bg-white border border-gray-100 rounded-3xl shadow-sm outline-none" />
          <div className="bg-white rounded-[40px] shadow-sm border border-gray-100 overflow-hidden">
            {filteredTransactions.map(t => (
              <div key={t.id} className="p-5 flex items-center justify-between border-b border-gray-50 last:border-0 hover:bg-gray-50/50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${t.type === 'income' ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-600'}`}>
                    {t.source === 'mpesa' ? '📩' : t.source === 'receipt' ? '📸' : '✍️'}
                  </div>
                  <div>
                    <p className="font-black text-xs uppercase tracking-tight">{t.merchant}</p>
                    <p className="text-[10px] text-gray-400">{t.date} • {t.category}</p>
                  </div>
                </div>
                <div className="flex items-center gap-4">
                  <p className={`font-black text-sm ${t.type === 'income' ? 'text-emerald-700' : 'text-gray-900'}`}>
                    {t.type === 'expense' ? '-' : '+'}{CURRENCY} {t.amount.toLocaleString()}
                  </p>
                  <button onClick={() => setEditingTransaction(t)} className="text-blue-500 hover:text-blue-700 p-2">✏️</button>
                  <button onClick={() => { if(confirm('Delete?')) onDeleteTransaction(t.id); }} className="text-red-300 hover:text-red-600 p-2">🗑️</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {editingTransaction && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black uppercase tracking-tighter">Edit Entry</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-gray-400">✖</button>
            </div>
            <form onSubmit={handleEditSave} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Merchant</label>
                <input type="text" value={editingTransaction.merchant} onChange={e => setEditingTransaction({...editingTransaction, merchant: e.target.value})} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Amount</label>
                <input type="number" value={editingTransaction.amount} onChange={e => setEditingTransaction({...editingTransaction, amount: Number(e.target.value)})} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Category</label>
                <select value={editingTransaction.category} onChange={e => setEditingTransaction({...editingTransaction, category: e.target.value as Category})} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <button type="submit" className="w-full bg-black text-white py-5 rounded-2xl font-black uppercase tracking-widest text-sm shadow-xl active:scale-95 transition-all mt-4">Save Changes</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default FinancialAnalysis;

import React, { useMemo } from 'react';
import { Transaction, Category, UserProfile } from '../types';
import { KENYA_TAX_BANDS, CURRENCY, SHIF_RATE, HOUSING_LEVY_RATE, PERSONAL_RELIEF_MONTHLY } from '../constants';

interface TaxEngineProps {
  transactions: Transaction[];
  profile: UserProfile;
  lang: 'en' | 'sw';
  onNavigate: (tab: any) => void;
}

const TaxEngine: React.FC<TaxEngineProps> = ({ transactions, profile, lang, onNavigate }) => {
  const taxStats = useMemo(() => {
    const gross = profile.monthlyIncome || 0;

    // 1. Calculate PAYE
    let remaining = gross;
    let paye = 0;
    let prevLimit = 0;
    for (const band of KENYA_TAX_BANDS) {
      const taxableInBand = Math.min(Math.max(0, gross - prevLimit), band.upTo - prevLimit);
      paye += taxableInBand * band.rate;
      prevLimit = band.upTo;
      if (gross <= band.upTo) break;
    }

    // 2. Levies
    const shif = gross * SHIF_RATE;
    const housingLevy = gross * HOUSING_LEVY_RATE;

    // 3. Reliefs
    const insuranceRelief = (profile.insurancePremium || 0) * 0.15;
    const personalRelief = PERSONAL_RELIEF_MONTHLY;
    const totalRelief = personalRelief + insuranceRelief;

    const netTax = Math.max(0, paye - totalRelief);
    const takeHome = gross - netTax - shif - housingLevy;

    // 4. Refund Potential from business expenses
    const bizExpenses = transactions
      .filter(tr => tr.isBusiness || tr.category === Category.BUSINESS)
      .reduce((sum, tr) => sum + tr.amount, 0);
    const refundPotential = (bizExpenses / 12) * 0.16; // Simplified estimate

    return { gross, paye, shif, housingLevy, netTax, takeHome, reliefs: totalRelief, refundPotential };
  }, [profile, transactions]);

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500">
      <div className="bg-red-600 text-white rounded-[40px] p-8 md:p-12 shadow-2xl relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-red-100 text-[10px] font-black uppercase tracking-widest mb-2">Monthly Tax Liability Preview</p>
          <h2 className="text-5xl font-black mb-6">{CURRENCY} {taxStats.netTax.toLocaleString()}</h2>
          <div className="flex gap-4">
             <div className="bg-white/10 p-4 rounded-3xl backdrop-blur-sm border border-white/5 flex-1">
               <p className="text-[9px] font-black uppercase text-red-100 mb-1">Take Home</p>
               <p className="text-lg font-black">{CURRENCY} {taxStats.takeHome.toLocaleString()}</p>
             </div>
             <div className="bg-white/10 p-4 rounded-3xl backdrop-blur-sm border border-white/5 flex-1 text-center">
               <p className="text-[9px] font-black uppercase text-red-100 mb-1">Refund Potential</p>
               <p className="text-lg font-black text-emerald-400">+{CURRENCY} {taxStats.refundPotential.toLocaleString()}</p>
             </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <section className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100">
          <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6">Tax Breakdown</h3>
          <div className="space-y-4">
            <TaxRow label="Gross Salary" value={taxStats.gross} />
            <TaxRow label="PAYE (Before Relief)" value={taxStats.paye} />
            <TaxRow label="Personal Relief" value={-2400} color="text-emerald-600" />
            <TaxRow label="Insurance Relief" value={-((profile.insurancePremium || 0) * 0.15)} color="text-emerald-600" />
            <div className="border-t border-gray-100 pt-4 mt-4">
              <TaxRow label="SHIF (2.75%)" value={taxStats.shif} />
              <TaxRow label="Housing Levy (1.5%)" value={taxStats.housingLevy} />
            </div>
          </div>
        </section>

        <section className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100">
          <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6">Optimization Tips</h3>
          <div className="space-y-6">
            <TaxTip icon="🏦" title="Housing Interest" desc="Your mortgage interest is deductible up to KES 300k p.a." />
            <TaxTip icon="🏥" title="Life Insurance" desc="Claim 15% relief on your premiums to lower your PAYE." />
            <TaxTip icon="💼" title="Business Expenses" desc="Freelancers can claim data, travel and tools as business costs." />
          </div>
        </section>
      </div>

      <button className="w-full bg-black text-white py-5 rounded-[28px] font-black uppercase tracking-widest text-sm shadow-xl border-b-4 border-emerald-800 active:scale-95 transition-all">Prepare My iTax Preview 🇰🇪</button>
    </div>
  );
};

const TaxRow: React.FC<{ label: string; value: number; color?: string }> = ({ label, value, color = "text-gray-900" }) => (
  <div className="flex justify-between items-center text-sm font-bold">
    <span className="text-gray-500 font-medium">{label}</span>
    <span className={color}>{CURRENCY} {Math.abs(value).toLocaleString()}</span>
  </div>
);

const TaxTip: React.FC<{ icon: string; title: string; desc: string }> = ({ icon, title, desc }) => (
  <div className="flex gap-4 items-start">
    <div className="w-10 h-10 bg-gray-50 rounded-xl flex items-center justify-center text-xl shrink-0">{icon}</div>
    <div>
      <h4 className="text-xs font-black uppercase tracking-tight">{title}</h4>
      <p className="text-[10px] text-gray-500 mt-1 leading-relaxed font-medium">{desc}</p>
    </div>
  </div>
);

export default TaxEngine;

import React, { useState, useMemo } from 'react';
import { Transaction, UserProfile, SavingsChallenge } from '../types';
import { CURRENCY } from '../constants';

interface GoalsProps {
  transactions: Transaction[];
  profile: UserProfile;
  challenges: SavingsChallenge[];
  onUpdateChallenges: (ch: SavingsChallenge[]) => void;
  onUpdateGoals: (goals: string[]) => void;
  lang: 'en' | 'sw';
}

const PRESET_TEMPLATES = [
  { id: 'chama100', name: 'Chama 100', seed: 100, increment: 100, weeks: 52, icon: '🤝', desc: 'The classic progressive saving challenge.', color: 'emerald' },
  { id: 'boda_save', name: 'Boda Fuel Save', seed: 50, increment: 50, weeks: 12, icon: '🏍️', desc: 'Quick save for maintenance.', color: 'blue' },
  { id: 'rent_guard', name: 'Rent Guardian', seed: 500, increment: 0, weeks: 4, icon: '🏠', desc: 'Weekly lock for rent.', color: 'purple' },
  { id: 'shamba', name: 'Plot Deposit', seed: 2000, increment: 500, weeks: 48, icon: '🏔️', desc: 'Aggressive saving for land.', color: 'amber' },
];

const Goals: React.FC<GoalsProps> = ({ transactions, profile, challenges, onUpdateChallenges, onUpdateGoals, lang }) => {
  const [newGoal, setNewGoal] = useState('');
  const [isCreatingChallenge, setIsCreatingChallenge] = useState(false);
  const [viewingChallenge, setViewingChallenge] = useState<SavingsChallenge | null>(null);
  const [challengeForm, setChallengeForm] = useState({ name: 'Challenge', seed: 50, increment: 50, weeks: 52 });

  const totalIncome = transactions.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
  const totalExpenses = transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
  const potentialSavings = Math.max(0, totalIncome - totalExpenses);

  const addGoal = () => {
    if (newGoal.trim() && !profile.financialGoals.includes(newGoal.trim())) {
      onUpdateGoals([...profile.financialGoals, newGoal.trim()]);
      setNewGoal('');
    }
  };

  const createChallenge = () => {
    const newCh: SavingsChallenge = {
      id: Math.random().toString(36).substr(2, 9),
      name: challengeForm.name,
      seedAmount: challengeForm.seed,
      weeklyIncrement: challengeForm.increment,
      durationWeeks: challengeForm.weeks,
      startDate: new Date().toISOString(),
      completedWeeks: []
    };
    onUpdateChallenges([...challenges, newCh]);
    setIsCreatingChallenge(false);
  };

  const deleteChallenge = (id: string) => {
    if (confirm("Stop this challenge?")) {
      onUpdateChallenges(challenges.filter(c => c.id !== id));
      setViewingChallenge(null);
    }
  };

  const toggleWeek = (challengeId: string, week: number) => {
    const newChallenges = challenges.map(c => {
      if (c.id === challengeId) {
        const completed = c.completedWeeks.includes(week)
          ? c.completedWeeks.filter(w => w !== week)
          : [...c.completedWeeks, week];
        return { ...c, completedWeeks: completed };
      }
      return c;
    });
    onUpdateChallenges(newChallenges);
    // Update the viewing modal state too
    const updated = newChallenges.find(c => c.id === challengeId);
    if (updated) setViewingChallenge(updated);
  };

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500 max-w-4xl mx-auto">
      <div className="bg-emerald-800 rounded-[40px] p-8 md:p-12 shadow-2xl relative overflow-hidden text-white border-b-8 border-red-600">
        <div className="relative z-10 text-center">
          <p className="text-emerald-100 text-[10px] font-black uppercase tracking-[0.3em] mb-4 opacity-80">Wealth Potential</p>
          <h2 className="text-5xl md:text-7xl font-black tracking-tighter mb-8">
            <span className="text-xl md:text-2xl opacity-50">{CURRENCY}</span> 
            <span className="text-emerald-400">{potentialSavings.toLocaleString()}</span>
          </h2>
        </div>
      </div>

      <section className="px-4 space-y-4">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Active Challenges</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {challenges.map(ch => (
            <button key={ch.id} onClick={() => setViewingChallenge(ch)} className="bg-white p-6 rounded-[32px] shadow-sm border border-gray-100 flex justify-between items-center group hover:border-emerald-700 transition-all">
              <div className="text-left">
                <h4 className="font-black uppercase text-sm tracking-tight">{ch.name}</h4>
                <p className="text-[10px] font-black text-emerald-700 uppercase tracking-widest mt-1">Week {ch.completedWeeks.length} / {ch.durationWeeks}</p>
              </div>
              <div className="w-10 h-10 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-700 group-hover:bg-emerald-700 group-hover:text-white transition-colors">→</div>
            </button>
          ))}
          <button onClick={() => setIsCreatingChallenge(true)} className="bg-gray-100 p-6 rounded-[32px] border-2 border-dashed border-gray-300 flex items-center justify-center gap-2 text-gray-500 font-black uppercase text-[10px] tracking-widest">
            <span className="text-lg">+</span> Create New
          </button>
        </div>
      </section>

      <section className="space-y-6 px-4">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Templates</h3>
        <div className="grid grid-cols-2 gap-4">
          {PRESET_TEMPLATES.map((tmpl) => (
            <button key={tmpl.id} onClick={() => { setChallengeForm({ name: tmpl.name, seed: tmpl.seed, increment: tmpl.increment, weeks: tmpl.weeks }); setIsCreatingChallenge(true); }} className="bg-white p-6 rounded-[32px] border border-gray-100 text-left hover:shadow-lg transition-all">
              <div className="text-3xl mb-4">{tmpl.icon}</div>
              <h4 className="font-black uppercase text-xs tracking-tight">{tmpl.name}</h4>
              <p className="text-[9px] font-black text-gray-400 mt-1 uppercase">{tmpl.weeks} Weeks</p>
            </button>
          ))}
        </div>
      </section>

      {/* CREATE MODAL */}
      {isCreatingChallenge && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-6">
              <h4 className="text-xl font-black uppercase tracking-tight">Setup Challenge</h4>
              <button onClick={() => setIsCreatingChallenge(false)} className="text-gray-400">✖</button>
            </div>
            <div className="space-y-4">
              <ChallengeInput label="Name" value={challengeForm.name} onChange={v => setChallengeForm({...challengeForm, name: v})} />
              <div className="grid grid-cols-2 gap-4">
                <ChallengeInput label="Start" type="number" value={challengeForm.seed} onChange={v => setChallengeForm({...challengeForm, seed: Number(v)})} />
                <ChallengeInput label="Increase" type="number" value={challengeForm.increment} onChange={v => setChallengeForm({...challengeForm, increment: Number(v)})} />
              </div>
              <ChallengeInput label="Weeks" type="number" value={challengeForm.weeks} onChange={v => setChallengeForm({...challengeForm, weeks: Number(v)})} />
              <button onClick={createChallenge} className="w-full py-5 rounded-2xl font-black uppercase tracking-widest text-sm bg-emerald-800 text-white shadow-xl mt-4">Launch 🚀</button>
            </div>
          </div>
        </div>
      )}

      {/* TRACKER MODAL */}
      {viewingChallenge && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center p-0 sm:p-6 animate-in slide-in-from-bottom-10 duration-300">
          <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[40px] p-8 max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h4 className="text-2xl font-black uppercase tracking-tighter">{viewingChallenge.name}</h4>
              <button onClick={() => setViewingChallenge(null)} className="bg-gray-100 p-2 rounded-full">✖</button>
            </div>

            <div className="grid grid-cols-2 gap-4 mb-8">
               <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100">
                 <p className="text-[9px] font-black uppercase text-emerald-800 mb-1">Weeks Done</p>
                 <p className="text-2xl font-black">{viewingChallenge.completedWeeks.length} / {viewingChallenge.durationWeeks}</p>
               </div>
               <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
                 <p className="text-[9px] font-black uppercase text-gray-400 mb-1">Current Target</p>
                 <p className="text-2xl font-black">{CURRENCY} {(viewingChallenge.seedAmount + (viewingChallenge.completedWeeks.length * viewingChallenge.weeklyIncrement)).toLocaleString()}</p>
               </div>
            </div>

            <div className="grid grid-cols-5 gap-2 mb-8">
              {[...Array(viewingChallenge.durationWeeks)].map((_, i) => {
                const weekNum = i + 1;
                const isCompleted = viewingChallenge.completedWeeks.includes(weekNum);
                return (
                  <button key={i} onClick={() => toggleWeek(viewingChallenge.id, weekNum)} className={`aspect-square rounded-xl flex items-center justify-center font-black text-xs transition-all border-2 ${isCompleted ? 'bg-emerald-800 border-emerald-900 text-white' : 'bg-gray-50 border-gray-100 text-gray-400'}`}>
                    {weekNum}
                  </button>
                );
              })}
            </div>

            <button onClick={() => deleteChallenge(viewingChallenge.id)} className="w-full text-red-500 font-black uppercase tracking-widest text-[10px] py-4">End Challenge Early</button>
          </div>
        </div>
      )}
    </div>
  );
};

const ChallengeInput: React.FC<{ label: string; value: any; onChange: (v: string) => void; type?: string }> = ({ label, value, onChange, type = 'text' }) => (
  <div className="space-y-1">
    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">{label}</label>
    <input type={type} value={value} onChange={e => onChange(e.target.value)} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold" />
  </div>
);

export default Goals;

