export default App;

import React, { useState, useMemo } from 'react';
import { Transaction, Category, Budget } from '../types';
import { CURRENCY } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface FinancialAnalysisProps {
  transactions: Transaction[];
  budgets: Budget[];
  onUpdateBudgets: (budgets: Budget[]) => void;
  onUpdateTransaction: (transaction: Transaction) => void;
  onDeleteTransaction: (id: string) => void;
  lang: 'en' | 'sw';
}

const FinancialAnalysis: React.FC<FinancialAnalysisProps> = ({ transactions, budgets, onUpdateBudgets, onUpdateTransaction, onDeleteTransaction, lang }) => {
  const [activeView, setActiveView] = useState<'logs' | 'analysis' | 'budget'>('analysis');
  const [search, setSearch] = useState('');
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [editingBudget, setEditingBudget] = useState<Category | null>(null);

  const now = new Date();
  const currentMonth = now.getMonth();

  const monthlyIncome = transactions
    .filter(t => t.type === 'income' && new Date(t.date).getMonth() === currentMonth)
    .reduce((sum, t) => sum + t.amount, 0);

  const monthlyExpense = transactions
    .filter(t => t.type === 'expense' && new Date(t.date).getMonth() === currentMonth)
    .reduce((sum, t) => sum + t.amount, 0);

  const netFlow = monthlyIncome - monthlyExpense;
  const flowRatio = monthlyIncome > 0 ? (monthlyExpense / monthlyIncome) * 100 : 0;

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => 
      t.merchant.toLowerCase().includes(search.toLowerCase()) || 
      t.category.toLowerCase().includes(search.toLowerCase())
    ).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, search]);

  const categoryData = useMemo(() => {
    const data: Record<string, number> = {};
    transactions.filter(t => t.type === 'expense' && new Date(t.date).getMonth() === currentMonth).forEach(t => {
      data[t.category] = (data[t.category] || 0) + t.amount;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [transactions, currentMonth]);

  const COLORS = ['#10b981', '#ef4444', '#065f46', '#f59e0b', '#3b82f6', '#8b5cf6', '#ec4899', '#6b7280'];

  const handleEditSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingTransaction) {
      onUpdateTransaction(editingTransaction);
      setEditingTransaction(null);
    }
  };

  const updateBudgetLimit = (category: Category, field: 'weeklyLimit' | 'monthlyLimit', value: number) => {
    const exists = budgets.find(b => b.category === category);
    if (exists) {
      onUpdateBudgets(budgets.map(b => b.category === category ? { ...b, [field]: value } : b));
    } else {
      onUpdateBudgets([...budgets, { category, weeklyLimit: 0, monthlyLimit: 0, [field]: value }]);
    }
  };

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500">
      <div className="flex bg-gray-200 p-1.5 rounded-[28px] sm:rounded-[36px] gap-1 shadow-inner max-w-md mx-auto">
        <button onClick={() => setActiveView('analysis')} className={`flex-1 py-3 rounded-[22px] font-black text-[10px] uppercase tracking-widest transition-all ${activeView === 'analysis' ? 'bg-white text-black shadow-md' : 'text-gray-400'}`}>Analysis</button>
        <button onClick={() => setActiveView('logs')} className={`flex-1 py-3 rounded-[22px] font-black text-[10px] uppercase tracking-widest transition-all ${activeView === 'logs' ? 'bg-white text-black shadow-md' : 'text-gray-400'}`}>Logs</button>
        <button onClick={() => setActiveView('budget')} className={`flex-1 py-3 rounded-[22px] font-black text-[10px] uppercase tracking-widest transition-all ${activeView === 'budget' ? 'bg-white text-black shadow-md' : 'text-gray-400'}`}>Budgets</button>
      </div>

      {activeView === 'analysis' && (
        <div className="space-y-8">
          <section className="bg-[#0A0D10] text-white rounded-[40px] p-8 border border-emerald-900/50 relative overflow-hidden">
            <div className="relative z-10 grid grid-cols-1 md:grid-cols-3 gap-8">
              <div className="space-y-2 text-center md:text-left">
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-[0.2em]">CASH FLOW</p>
                <h4 className="text-3xl font-black">{CURRENCY} {netFlow.toLocaleString()}</h4>
              </div>
              <div className="space-y-2 text-center md:text-left">
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-[0.2em]">BURN RATE</p>
                <h4 className="text-3xl font-black">{flowRatio.toFixed(1)}%</h4>
              </div>
              <div className="space-y-2 text-center md:text-left">
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-[0.2em]">INCOME</p>
                <h4 className="text-3xl font-black">{CURRENCY} {monthlyIncome.toLocaleString()}</h4>
              </div>
            </div>
          </section>

          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100">
            <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6">Spending Breakdown</h3>
            <div className="h-[300px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={categoryData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                    {categoryData.map((_, index) => <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />)}
                  </Pie>
                  <Tooltip />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            </div>
          </div>
        </div>
      )}

      {activeView === 'logs' && (
        <div className="space-y-4">
          <input type="text" placeholder="Search..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full p-4 bg-white border border-gray-100 rounded-3xl shadow-sm outline-none" />
          <div className="bg-white rounded-[40px] shadow-sm border border-gray-100 overflow-hidden">
            {filteredTransactions.map(t => (
              <div key={t.id} className="p-5 flex items-center justify-between border-b border-gray-50 last:border-0 hover:bg-gray-50/50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${t.type === 'income' ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-600'}`}>
                    {t.source === 'mpesa' ? '📩' : t.source === 'receipt' ? '📸' : '✍️'}
                  </div>
                  <div className="max-w-[120px] sm:max-w-none">
                    <p className="font-black text-xs uppercase tracking-tight truncate">{t.merchant}</p>
                    <p className="text-[10px] text-gray-400">{t.date} • {t.category}</p>
                  </div>
                </div>
                <div className="flex items-center gap-3">
                  <p className={`font-black text-sm ${t.type === 'income' ? 'text-emerald-700' : 'text-gray-900'}`}>
                    {t.type === 'expense' ? '-' : '+'}{CURRENCY} {t.amount.toLocaleString()}
                  </p>
                  <button onClick={() => setEditingTransaction(t)} className="text-blue-500 hover:text-blue-700 p-2 text-lg">✏️</button>
                  <button onClick={() => { if(confirm('Delete?')) onDeleteTransaction(t.id); }} className="text-red-300 hover:text-red-600 p-2 text-lg">🗑️</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeView === 'budget' && (
        <div className="space-y-6">
          <section className="bg-emerald-800 text-white rounded-[40px] p-8 shadow-xl relative overflow-hidden">
             <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-2 opacity-80">Budget Summary</h3>
             <p className="text-4xl font-black">{CURRENCY} {monthlyExpense.toLocaleString()} spent</p>
             <p className="text-[10px] font-black uppercase tracking-widest mt-2 opacity-50">This month so far</p>
          </section>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {Object.values(Category).filter(cat => cat !== Category.SALARY && cat !== Category.FREELANCE).map(cat => {
              const budget = budgets.find(b => b.category === cat) || { category: cat, weeklyLimit: 0, monthlyLimit: 0 };
              const spentThisMonth = transactions.filter(t => t.category === cat && t.type === 'expense' && new Date(t.date).getMonth() === currentMonth).reduce((sum, t) => sum + t.amount, 0);
              const progress = budget.monthlyLimit > 0 ? (spentThisMonth / budget.monthlyLimit) * 100 : 0;

              return (
                <div key={cat} className="bg-white p-6 rounded-[32px] border border-gray-100 shadow-sm space-y-4">
                  <div className="flex justify-between items-center">
                    <h4 className="text-xs font-black uppercase tracking-tight truncate mr-2">{cat}</h4>
                    <button onClick={() => setEditingBudget(cat)} className="text-[9px] font-black text-emerald-800 uppercase bg-emerald-50 px-3 py-1 rounded-full">Set Limit</button>
                  </div>

                  {budget.monthlyLimit > 0 ? (
                    <div className="space-y-2">
                       <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-500">
                         <span>Spent: {spentThisMonth.toLocaleString()}</span>
                         <span>Limit: {budget.monthlyLimit.toLocaleString()}</span>
                       </div>
                       <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                          <div className={`h-full transition-all duration-700 ${progress > 100 ? 'bg-red-600' : 'bg-emerald-600'}`} style={{ width: `${Math.min(100, progress)}%` }}></div>
                       </div>
                       <p className={`text-[9px] font-black uppercase text-center ${progress > 100 ? 'text-red-600' : 'text-emerald-800'}`}>
                         {progress > 100 ? `Over by ${CURRENCY} ${(spentThisMonth - budget.monthlyLimit).toLocaleString()}` : `${CURRENCY} ${(budget.monthlyLimit - spentThisMonth).toLocaleString()} left`}
                       </p>
                    </div>
                  ) : (
                    <p className="text-[10px] text-gray-300 italic">No budget set for this category.</p>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {editingBudget && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
           <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-black uppercase tracking-tight">Set Budget: {editingBudget}</h3>
                <button onClick={() => setEditingBudget(null)} className="text-gray-400">✖</button>
              </div>
              <div className="space-y-6">
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Monthly Limit ({CURRENCY})</label>
                   <input 
                     type="number" 
                     placeholder="0"
                     value={budgets.find(b => b.category === editingBudget)?.monthlyLimit || ''}
                     onChange={(e) => updateBudgetLimit(editingBudget, 'monthlyLimit', Number(e.target.value))}
                     className="w-full p-5 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-black text-2xl"
                   />
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Weekly Limit ({CURRENCY})</label>
                   <input 
                     type="number" 
                     placeholder="0"
                     value={budgets.find(b => b.category === editingBudget)?.weeklyLimit || ''}
                     onChange={(e) => updateBudgetLimit(editingBudget, 'weeklyLimit', Number(e.target.value))}
                     className="w-full p-5 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-black text-2xl"
                   />
                </div>
                <button onClick={() => setEditingBudget(null)} className="w-full bg-black text-white py-5 rounded-2xl font-black uppercase tracking-widest text-sm shadow-xl active:scale-95">Save Budget</button>
              </div>
           </div>
        </div>
      )}

      {editingTransaction && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black uppercase tracking-tighter">Edit Entry</h3>
              <button onClick={() => setEditingTransaction(null)} className="text-gray-400">✖</button>
            </div>
            <form onSubmit={handleEditSave} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Merchant</label>
                <input type="text" value={editingTransaction.merchant} onChange={e => setEditingTransaction({...editingTransaction, merchant: e.target.value})} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Amount</label>
                <input type="number" value={editingTransaction.amount} onChange={e => setEditingTransaction({...editingTransaction, amount: Number(e.target.value)})} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">Category</label>
                <select value={editingTransaction.category} onChange={e => setEditingTransaction({...editingTransaction, category: e.target.value as Category})} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold">
                  {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <button type="submit" className="w-full bg-black text-white py-5 rounded-2xl font-black uppercase tracking-widest text-sm shadow-xl active:scale-95 transition-all mt-4">Save Changes</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default FinancialAnalysis;

import React, { useState, useMemo } from 'react';
import { Transaction, UserProfile, SavingsChallenge } from '../types';
import { CURRENCY } from '../constants';

interface GoalsProps {
  transactions: Transaction[];
  profile: UserProfile;
  challenges: SavingsChallenge[];
  onUpdateChallenges: (ch: SavingsChallenge[]) => void;
  onUpdateGoals: (goals: string[]) => void;
  lang: 'en' | 'sw';
}

const PRESET_TEMPLATES = [
  { id: 'chama100', name: 'Chama 100', seed: 100, increment: 100, weeks: 52, icon: '🤝', desc: 'Progressive weekly savings.', color: 'emerald' },
  { id: 'emergency', name: 'Emergency Fund', seed: 500, increment: 0, weeks: 12, icon: '🛡️', desc: 'Secure your peace of mind.', color: 'blue' },
  { id: 'school_fees', name: 'School Fees Goal', seed: 1000, increment: 0, weeks: 20, icon: '📚', desc: 'Prepare for next term.', color: 'purple' },
  { id: 'plot_deposit', name: 'Plot Deposit', seed: 5000, increment: 500, weeks: 48, icon: '🏔️', desc: 'Saving for your first land.', color: 'amber' },
  { id: 'holiday', name: 'Diani Holiday', seed: 200, increment: 100, weeks: 16, icon: '🏖️', desc: 'Save for that beach trip.', color: 'red' },
  { id: 'business_cap', name: 'Business Capital', seed: 2000, increment: 0, weeks: 24, icon: '💼', desc: 'Start your own hustle.', color: 'indigo' },
];

const Goals: React.FC<GoalsProps> = ({ transactions, profile, challenges, onUpdateChallenges, onUpdateGoals, lang }) => {
  const [newGoal, setNewGoal] = useState('');
  const [isCreatingChallenge, setIsCreatingChallenge] = useState(false);
  const [viewingChallenge, setViewingChallenge] = useState<SavingsChallenge | null>(null);
  const [challengeForm, setChallengeForm] = useState({ name: 'Challenge', seed: 50, increment: 50, weeks: 52 });

  const totalIncome = transactions.filter(t => t.type === 'income').reduce((sum, t) => sum + t.amount, 0);
  const totalExpenses = transactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + t.amount, 0);
  const potentialSavings = Math.max(0, totalIncome - totalExpenses);

  const addGoal = (e: React.FormEvent) => {
    e.preventDefault();
    if (newGoal.trim() && !profile.financialGoals.includes(newGoal.trim())) {
      onUpdateGoals([...profile.financialGoals, newGoal.trim()]);
      setNewGoal('');
    }
  };

  const createChallenge = () => {
    const newCh: SavingsChallenge = {
      id: Math.random().toString(36).substr(2, 9),
      name: challengeForm.name,
      seedAmount: challengeForm.seed,
      weeklyIncrement: challengeForm.increment,
      durationWeeks: challengeForm.weeks,
      startDate: new Date().toISOString(),
      completedWeeks: []
    };
    onUpdateChallenges([...challenges, newCh]);
    setIsCreatingChallenge(false);
  };

  const toggleWeek = (challengeId: string, week: number) => {
    const newChallenges = challenges.map(c => {
      if (c.id === challengeId) {
        const completed = c.completedWeeks.includes(week)
          ? c.completedWeeks.filter(w => w !== week)
          : [...c.completedWeeks, week];
        return { ...c, completedWeeks: completed };
      }
      return c;
    });
    onUpdateChallenges(newChallenges);
    const updated = newChallenges.find(c => c.id === challengeId);
    if (updated) setViewingChallenge(updated);
  };

  return (
    <div className="space-y-10 pb-20 animate-in fade-in duration-500 max-w-4xl mx-auto">
      {/* Wealth Header */}
      <section className="bg-emerald-800 rounded-[50px] p-10 md:p-14 shadow-2xl relative overflow-hidden text-white border-b-8 border-red-600">
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500/20 blur-[100px] rounded-full"></div>
        <div className="relative z-10 text-center space-y-4">
          <p className="text-emerald-100 text-[10px] font-black uppercase tracking-[0.4em] opacity-80">Net Monthly Capacity</p>
          <h2 className="text-5xl md:text-8xl font-black tracking-tighter flex items-center justify-center gap-2">
            <span className="text-xl md:text-3xl opacity-50 font-medium">{CURRENCY}</span> 
            <span className="text-emerald-400 drop-shadow-lg">{potentialSavings.toLocaleString()}</span>
          </h2>
          <p className="text-emerald-200 text-xs font-bold uppercase tracking-widest max-w-xs mx-auto">This is your potential seed for wealth creation.</p>
        </div>
      </section>

      {/* Active Challenges Grid */}
      <section className="px-2 space-y-6">
        <div className="flex justify-between items-center px-4">
          <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Active Challenges</h3>
          <span className="bg-gray-100 text-gray-500 px-3 py-1 rounded-full text-[9px] font-black">{challenges.length} active</span>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {challenges.map(ch => (
            <button key={ch.id} onClick={() => setViewingChallenge(ch)} className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100 flex flex-col justify-between group hover:border-emerald-700 hover:shadow-xl transition-all text-left">
              <div className="mb-6">
                <h4 className="font-black uppercase text-lg tracking-tight text-gray-900">{ch.name}</h4>
                <p className="text-[10px] font-black text-emerald-700 uppercase tracking-widest mt-1">
                  Week {ch.completedWeeks.length} of {ch.durationWeeks}
                </p>
              </div>
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden mb-4">
                <div className="h-full bg-emerald-600 transition-all duration-1000" style={{ width: `${(ch.completedWeeks.length / ch.durationWeeks) * 100}%` }}></div>
              </div>
              <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-gray-400">
                <span>View Progress</span>
                <span className="text-emerald-800">→</span>
              </div>
            </button>
          ))}
          <button onClick={() => setIsCreatingChallenge(true)} className="bg-gray-50 p-8 rounded-[40px] border-4 border-dashed border-gray-200 flex flex-col items-center justify-center gap-2 text-gray-400 hover:bg-white hover:border-emerald-200 transition-all">
            <span className="text-4xl">+</span>
            <span className="font-black uppercase text-[10px] tracking-widest">Create New Hustle Challenge</span>
          </button>
        </div>
      </section>

      {/* Challenges Marketplace */}
      <section className="space-y-6 px-2">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest px-4">Wealth Templates</h3>
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
          {PRESET_TEMPLATES.map((tmpl) => (
            <button key={tmpl.id} onClick={() => { setChallengeForm({ name: tmpl.name, seed: tmpl.seed, increment: tmpl.increment, weeks: tmpl.weeks }); setIsCreatingChallenge(true); }} className="bg-white p-6 rounded-[32px] border border-gray-100 text-left hover:scale-105 transition-all shadow-sm">
              <div className="text-3xl mb-4">{tmpl.icon}</div>
              <h4 className="font-black uppercase text-[10px] tracking-tight text-gray-900 leading-tight">{tmpl.name}</h4>
              <p className="text-[9px] font-black text-emerald-800 mt-1 uppercase opacity-60">{tmpl.weeks} Weeks</p>
            </button>
          ))}
        </div>
      </section>

      {/* Wealth Milestones List */}
      <section className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100 space-y-6 mx-2">
        <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Personal Wealth Milestones</h3>
        <div className="space-y-3">
          {profile.financialGoals.map((goal, idx) => (
            <div key={idx} className="flex justify-between items-center p-5 bg-gray-50 rounded-2xl border border-gray-100 group">
              <span className="text-sm font-black uppercase tracking-tight text-gray-800">{goal}</span>
              <button onClick={() => onUpdateGoals(profile.financialGoals.filter((_, i) => i !== idx))} className="text-red-300 hover:text-red-600 transition-colors">🗑️</button>
            </div>
          ))}
          <form onSubmit={addGoal} className="flex gap-2">
            <input type="text" placeholder="Add a new milestone (e.g. Build House)" value={newGoal} onChange={e => setNewGoal(e.target.value)} className="flex-1 p-4 bg-gray-100 border-none rounded-2xl focus:ring-2 focus:ring-emerald-800 outline-none text-sm font-bold" />
            <button type="submit" className="bg-black text-white px-6 rounded-2xl font-black text-xl hover:bg-emerald-800 active:scale-95">+</button>
          </form>
        </div>
      </section>

      {/* TRACKER MODAL */}
      {viewingChallenge && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center p-0 sm:p-6 animate-in slide-in-from-bottom-10 duration-300">
          <div className="bg-white w-full max-w-lg rounded-t-[50px] sm:rounded-[50px] p-10 max-h-[90vh] overflow-y-auto shadow-2xl border-t-8 border-emerald-800">
            <div className="flex justify-between items-center mb-8">
              <h4 className="text-3xl font-black uppercase tracking-tighter">{viewingChallenge.name}</h4>
              <button onClick={() => setViewingChallenge(null)} className="bg-gray-100 p-3 rounded-full text-lg">✖</button>
            </div>

            <div className="grid grid-cols-2 gap-4 mb-10">
               <div className="bg-emerald-50 p-8 rounded-[40px] border border-emerald-100 text-center">
                 <p className="text-[10px] font-black uppercase text-emerald-800 mb-2 tracking-widest">Progress</p>
                 <p className="text-3xl font-black">{viewingChallenge.completedWeeks.length} / {viewingChallenge.durationWeeks}</p>
               </div>
               <div className="bg-gray-50 p-8 rounded-[40px] border border-gray-100 text-center">
                 <p className="text-[10px] font-black uppercase text-gray-400 mb-2 tracking-widest">Next Target</p>
                 <p className="text-3xl font-black text-emerald-800">
                    {CURRENCY} {(viewingChallenge.seedAmount + (viewingChallenge.completedWeeks.length * viewingChallenge.weeklyIncrement)).toLocaleString()}
                 </p>
               </div>
            </div>

            <div className="grid grid-cols-5 gap-3 mb-10">
              {[...Array(viewingChallenge.durationWeeks)].map((_, i) => {
                const weekNum = i + 1;
                const isCompleted = viewingChallenge.completedWeeks.includes(weekNum);
                return (
                  <button key={i} onClick={() => toggleWeek(viewingChallenge.id, weekNum)} className={`aspect-square rounded-2xl flex items-center justify-center font-black text-xs transition-all border-2 ${isCompleted ? 'bg-emerald-800 border-emerald-900 text-white shadow-lg' : 'bg-gray-50 border-gray-100 text-gray-400 hover:border-emerald-200'}`}>
                    {weekNum}
                  </button>
                );
              })}
            </div>

            <button onClick={() => { if(confirm("Stop challenge?")) { onUpdateChallenges(challenges.filter(c => c.id !== viewingChallenge.id)); setViewingChallenge(null); }}} className="w-full text-red-500 font-black uppercase tracking-widest text-[11px] py-4 bg-red-50 rounded-2xl">Abort Financial Mission</button>
          </div>
        </div>
      )}

      {/* CREATE MODAL */}
      {isCreatingChallenge && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[40px] p-8 shadow-2xl border-t-8 border-black">
            <div className="flex justify-between items-center mb-6">
              <h4 className="text-xl font-black uppercase tracking-tight">Setup Mission</h4>
              <button onClick={() => setIsCreatingChallenge(false)} className="text-gray-400">✖</button>
            </div>
            <div className="space-y-4">
              <ChallengeInput label="Challenge Name" value={challengeForm.name} onChange={v => setChallengeForm({...challengeForm, name: v})} />
              <div className="grid grid-cols-2 gap-4">
                <ChallengeInput label="Week 1 Aim" type="number" value={challengeForm.seed} onChange={v => setChallengeForm({...challengeForm, seed: Number(v)})} />
                <ChallengeInput label="Step Increase" type="number" value={challengeForm.increment} onChange={v => setChallengeForm({...challengeForm, increment: Number(v)})} />
              </div>
              <ChallengeInput label="Duration (Weeks)" type="number" value={challengeForm.weeks} onChange={v => setChallengeForm({...challengeForm, weeks: Number(v)})} />
              <button onClick={createChallenge} className="w-full py-5 rounded-2xl font-black uppercase tracking-widest text-sm bg-black text-white shadow-xl mt-6">Confirm Setup</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const ChallengeInput: React.FC<{ label: string; value: any; onChange: (v: string) => void; type?: string }> = ({ label, value, onChange, type = 'text' }) => (
  <div className="space-y-1">
    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-1">{label}</label>
    <input type={type} value={value} onChange={e => onChange(e.target.value)} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl outline-none font-bold" />
  </div>
);

export default Goals;

import React, { useState } from 'react';
import { Transaction, Category } from '../types';
import ReceiptScanner from './ReceiptScanner';
import MpesaInput from './MpesaInput';
import { CURRENCY, TRANSLATIONS } from '../constants';

interface AddTransactionProps {
  onAdd: (t: Transaction) => void;
  lang: 'en' | 'sw';
}

const AddTransaction: React.FC<AddTransactionProps> = ({ onAdd, lang }) => {
  const t = TRANSLATIONS[lang];
  const [method, setMethod] = useState<'receipt' | 'mpesa' | 'manual'>('manual');
  const [manualType, setManualType] = useState<'expense' | 'income'>('expense');
  const [formData, setFormData] = useState({
    amount: '',
    merchant: '',
    category: Category.OTHER,
    date: new Date().toISOString().split('T')[0],
  });

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.amount || !formData.merchant) return;

    onAdd({
      id: Math.random().toString(36).substr(2, 9),
      date: formData.date,
      merchant: formData.merchant,
      amount: Number(formData.amount),
      category: formData.category,
      type: manualType,
      source: 'manual',
    });
  };

  return (
    <div className="space-y-6 sm:space-y-10 pb-12 animate-in slide-in-from-bottom-4 duration-500 max-w-3xl mx-auto">
      <div className="flex bg-gray-200 p-1.5 rounded-[28px] sm:rounded-[36px] gap-1 shadow-inner">
        <TabBtn active={method === 'manual'} onClick={() => setMethod('manual')} label={t.quick_cash} />
        <TabBtn active={method === 'receipt'} onClick={() => setMethod('receipt')} label={t.scan_receipt} />
        <TabBtn active={method === 'mpesa'} onClick={() => setMethod('mpesa')} label="M-Pesa Sync" />
      </div>

      <div className="w-full">
        {method === 'receipt' && <ReceiptScanner onAdd={onAdd} />}
        {method === 'mpesa' && <MpesaInput onAdd={onAdd} />}

        {method === 'manual' && (
          <div className="bg-white rounded-[40px] p-6 sm:p-10 shadow-sm border border-gray-100">
            <div className="flex justify-center mb-8 sm:mb-12 bg-gray-50 p-2 rounded-2xl border border-gray-100 max-w-sm mx-auto">
              <button 
                onClick={() => setManualType('expense')}
                className={`flex-1 py-3 px-6 rounded-xl font-black text-[10px] sm:text-xs uppercase tracking-widest transition-all ${manualType === 'expense' ? 'bg-red-600 text-white shadow-lg' : 'text-gray-400'}`}
              >
                Expense
              </button>
              <button 
                onClick={() => setManualType('income')}
                className={`flex-1 py-3 px-6 rounded-xl font-black text-[10px] sm:text-xs uppercase tracking-widest transition-all ${manualType === 'income' ? 'bg-emerald-800 text-white shadow-lg' : 'text-gray-400'}`}
              >
                Income
              </button>
            </div>

            <form onSubmit={handleManualSubmit} className="space-y-6 sm:space-y-8">
              <div className="space-y-2 text-center">
                <label className="text-[10px] sm:text-xs font-black text-gray-400 uppercase tracking-widest block">
                  {manualType === 'expense' ? t.spending_total : 'Total Inflow'} ({CURRENCY})
                </label>
                <input 
                  required
                  type="number"
                  placeholder="0.00"
                  value={formData.amount}
                  onChange={e => setFormData({...formData, amount: e.target.value})}
                  className="w-full max-w-xs mx-auto block p-5 bg-transparent border-b-4 border-gray-100 focus:border-emerald-700 outline-none text-4xl sm:text-5xl font-black text-gray-900 text-center transition-all"
                />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 sm:gap-8 pt-4">
                <div className="space-y-2">
                  <label className="text-[10px] sm:text-xs font-black text-gray-400 uppercase tracking-widest px-2">
                    {manualType === 'expense' ? 'Merchant / Recipient' : 'Payer / Source'}
                  </label>
                  <input 
                    required
                    type="text"
                    placeholder={manualType === 'expense' ? 'e.g. Mama Mboga' : 'e.g. Salary'}
                    value={formData.merchant}
                    onChange={e => setFormData({...formData, merchant: e.target.value})}
                    className="w-full p-4 sm:p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none font-bold text-gray-800"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] sm:text-xs font-black text-gray-400 uppercase tracking-widest px-2">Category</label>
                  <select 
                    value={formData.category}
                    onChange={e => setFormData({...formData, category: e.target.value as Category})}
                    className="w-full p-4 sm:p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none font-bold text-gray-800 appearance-none shadow-sm cursor-pointer"
                  >
                    {Object.values(Category).map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>

                <div className="space-y-2 md:col-span-2">
                  <label className="text-[10px] sm:text-xs font-black text-gray-400 uppercase tracking-widest px-2">Transaction Date</label>
                  <input 
                    type="date"
                    required
                    value={formData.date}
                    onChange={e => setFormData({...formData, date: e.target.value})}
                    className="w-full p-4 sm:p-5 bg-gray-50 border border-gray-100 rounded-[24px] focus:ring-4 focus:ring-emerald-100 outline-none font-bold text-gray-800 block cursor-pointer appearance-none"
                    style={{ minHeight: '64px' }}
                  />
                </div>
              </div>

              <div className="pt-4 max-w-sm mx-auto">
                <button 
                  type="submit"
                  className={`w-full py-5 rounded-[28px] font-black uppercase tracking-widest text-sm shadow-xl transition-all active:scale-95 ${manualType === 'expense' ? 'bg-red-600 text-white shadow-red-100 border-b-4 border-black' : 'bg-emerald-800 text-white shadow-emerald-100 border-b-4 border-black'}`}
                >
                  {manualType === 'expense' ? 'Record Matumizi' : 'Save Income Inflow'}
                </button>
              </div>
            </form>
          </div>
        )}
      </div>
    </div>
  );
};

